INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_greeting_A1_01','hello','/həˈloʊ/','interjection','안녕','A friendly greeting used when meeting someone.','She said {hello} to her neighbor every morning.','그녀는 매일 아침 이웃에게 안녕이라고 했어요.','hello','A1','greeting',1,'people greeting smiling waving'),
('w_greeting_A1_02','hi','/haɪ/','interjection','안녕, 하이','An informal greeting.','He waved and said {hi} across the room.','그는 방 너머로 손을 흔들며 하이 라고 했어요.','hi','A1','greeting',1,'friends waving hello casual'),
('w_greeting_A1_03','goodbye','/ˌɡʊdˈbaɪ/','interjection','안녕히 가세요','A farewell said when parting from someone.','She said {goodbye} and walked out the door.','그녀는 안녕히 가세요 라고 하고 문 밖으로 나갔어요.','goodbye','A1','greeting',1,'people waving farewell door'),
('w_greeting_A1_04','bye','/baɪ/','interjection','잘 가, 바이','An informal farewell.','He waved and said {bye} at the end of class.','수업이 끝나고 그는 손을 흔들며 잘 가 라고 했어요.','bye','A1','greeting',1,'students waving goodbye school'),
('w_greeting_A1_05','please','/pliːz/','adverb','부탁드려요, 제발','Used to add politeness to a request.','Could you help me, {please}?','저 좀 도와주실 수 있나요, 부탁드려요.','please','A1','greeting',1,'polite request hands together'),
('w_greeting_A1_06','thank you','/ˈθæŋk juː/','phrase','감사합니다','An expression of gratitude.','She smiled and said {thank you} sincerely.','그녀는 미소 지으며 진심으로 감사합니다 라고 했어요.','thank you','A1','greeting',1,'person smiling grateful thankful'),
('w_greeting_A1_07','sorry','/ˈsɒri/','interjection','미안해요, 죄송합니다','Used to apologize or express regret.','He said {sorry} after bumping into someone.','그는 누군가와 부딪힌 후 죄송합니다 라고 했어요.','sorry','A1','greeting',1,'person apologizing sorry expression'),
('w_greeting_A1_08','yes','/jɛs/','adverb','네, 예','Used to give a positive response.','She nodded and said {yes} to the invitation.','그녀는 고개를 끄덕이며 초대에 네 라고 했어요.','yes','A1','greeting',1,'person nodding agreement smiling'),
('w_greeting_A1_09','no','/noʊ/','adverb','아니요','Used to give a negative response.','He shook his head and said {no} politely.','그는 정중하게 고개를 흔들며 아니요 라고 했어요.','no','A1','greeting',1,'person shaking head politely'),
('w_greeting_A1_10','name','/neɪm/','noun','이름','The word used to identify a person.','My {name} is Jiyeon — nice to meet you!','제 이름은 지연이에요 — 반갑습니다!','name','A1','greeting',1,'name tag label identity'),
('w_greeting_A1_11','nice','/naɪs/','adjective','좋은, 반가운','Pleasant or kind.','It was {nice} to see you again after so long.','오랜만에 다시 만나니 너무 반가웠어요.','nice','A1','greeting',1,'happy reunion friends smiling'),
('w_greeting_A1_12','meet','/miːt/','verb','만나다','To encounter or be introduced to someone.','I''d love to {meet} your friends someday.','언젠가 당신의 친구들을 만나고 싶어요.','meet','A1','greeting',1,'people meeting handshake introduction'),
('w_greeting_A1_13','good morning','/ɡʊd ˈmɔːrnɪŋ/','phrase','좋은 아침이에요','A greeting said in the morning.','She called out {good morning} as she arrived.','그녀는 도착하면서 좋은 아침이에요 라고 말했어요.','good morning','A1','greeting',1,'morning sunrise coffee greeting'),
('w_greeting_A1_14','good evening','/ɡʊd ˈiːvnɪŋ/','phrase','좋은 저녁이에요','A greeting said in the evening.','He opened the door and said {good evening}.','그는 문을 열고 좋은 저녁이에요 라고 했어요.','good evening','A1','greeting',1,'evening sunset door greeting'),
('w_greeting_A1_15','good night','/ɡʊd naɪt/','phrase','좋은 밤이에요, 안녕히 주무세요','Said when someone is going to sleep.','She tucked him in and said {good night}.','그녀는 이불을 덮어주며 안녕히 주무세요 라고 했어요.','good night','A1','greeting',1,'nighttime bedroom sleeping farewell'),
('w_greeting_A1_16','welcome','/ˈwɛlkəm/','interjection','환영해요','Used to greet someone arriving somewhere.','The host said {welcome} and opened the door wide.','주인은 환영해요 라고 하며 문을 활짝 열었어요.','welcome','A1','greeting',1,'host door open welcoming smile'),
('w_greeting_A1_17','fine','/faɪn/','adjective','좋아요, 잘 지내요','Feeling well or in good condition.','I''m {fine}, thanks for asking!','잘 지내요, 물어봐 주셔서 감사해요!','fine','A1','greeting',1,'person smiling thumbs up okay'),
('w_greeting_A1_18','how','/haʊ/','adverb','어떻게, 어떤','Used to ask about condition or manner.','"{How} are you?" is the most common greeting.','어떻게 지내세요 는 가장 흔한 인사예요.','How','A1','greeting',1,'question speech bubble conversation'),
('w_greeting_A1_19','you','/juː/','pronoun','당신, 너','Used to refer to the person being spoken to.','Nice to see {you} here today!','오늘 여기서 만나게 되어 반가워요!','you','A1','greeting',1,'pointing person conversation'),
('w_greeting_A1_20','my','/maɪ/','pronoun','나의','Belonging to the speaker.','Let me introduce {my} friend to you.','제 친구를 소개할게요.','my','A1','greeting',1,'person self introduction gesture'),
('w_greeting_A1_21','friend','/frɛnd/','noun','친구','A person with whom you have a bond of affection.','This is my {friend} Minju.','이쪽은 제 친구 민주예요.','friend','A1','greeting',1,'two friends smiling together'),
('w_greeting_A1_22','see','/siː/','verb','보다, 만나다','To encounter or observe.','It''s great to {see} you again!','다시 만나게 되어 정말 기뻐요!','see','A1','greeting',1,'eyes looking happy reunion'),
('w_greeting_A1_23','again','/əˈɡɛn/','adverb','다시, 또','One more time, or after a pause.','Nice to see you {again}!','다시 만나서 반가워요!','again','A1','greeting',1,'reunion meeting second time'),
('w_greeting_A1_24','old','/oʊld/','adjective','오래된','Having a long relationship or past.','She''s an {old} friend from school.','그녀는 학교 때 오래된 친구예요.','old','A1','greeting',1,'longtime friends smiling memory'),
('w_greeting_A1_25','new','/njuː/','adjective','새로운','Existing for only a short time;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_greeting_A2_01','introduce','/ˌɪntrəˈdjuːs/','verb','소개하다','To present someone by name to another person.','Let me {introduce} myself — I''m Sujin.','제 소개를 할게요 — 저는 수진이에요.','introduce','A2','greeting',1,'person self introduction gesture'),
('w_greeting_A2_02','greet','/ɡriːt/','verb','인사하다','To say hello or welcome someone.','She always {greets} visitors with a warm smile.','그녀는 항상 따뜻한 미소로 방문객에게 인사해요.','greets','A2','greeting',1,'warm smile greeting visitor'),
('w_greeting_A2_03','farewell','/ˌfɛrˈwɛl/','noun','작별 인사','An expression said when parting from someone.','They held a {farewell} party for their coworker.','그들은 동료를 위해 작별 파티를 열었어요.','farewell','A2','greeting',2,'farewell party goodbye friends'),
('w_greeting_A2_04','handshake','/ˈhændʃeɪk/','noun','악수','An act of shaking hands as a greeting.','He offered a firm {handshake} when they first met.','그들이 처음 만났을 때 그는 힘차게 악수를 건넸어요.','handshake','A2','greeting',1,'handshake business first meeting'),
('w_greeting_A2_05','polite','/pəˈlaɪt/','adjective','예의 바른','Having good manners and respect for others.','It is {polite} to make eye contact when greeting.','인사할 때 눈을 맞추는 것이 예의 바른 행동이에요.','polite','A2','greeting',2,'eye contact respectful conversation'),
('w_greeting_A2_06','friendly','/ˈfrɛndli/','adjective','친근한, 다정한','Kind and pleasant toward other people.','She gave a {friendly} wave as he walked in.','그가 들어오자 그녀는 친근하게 손을 흔들었어요.','friendly','A2','greeting',1,'waving friendly open body language'),
('w_greeting_A2_07','casual','/ˈkæʒuəl/','adjective','격식 없는, 캐주얼한','Relaxed and informal in manner.','They exchanged a few {casual} words in the hallway.','그들은 복도에서 격식 없는 대화를 나눴어요.','casual','A2','greeting',2,'informal chat hallway relaxed'),
('w_greeting_A2_08','formal','/ˈfɔːrməl/','adjective','격식 있는','Done in accordance with rules or conventions.','The introduction was quite {formal} and stiff.','소개가 꽤 격식 있고 딱딱했어요.','formal','A2','greeting',2,'formal meeting suit business'),
('w_greeting_A2_09','wave','/weɪv/','verb','손을 흔들다','To move your hand back and forth as a greeting.','She {waved} goodbye from the window.','그녀는 창문에서 손을 흔들며 작별 인사를 했어요.','waved','A2','greeting',1,'waving window departure goodbye'),
('w_greeting_A2_10','chat','/tʃæt/','verb','잡담하다, 이야기하다','To talk in a friendly and informal way.','We {chatted} for a while after the meeting.','회의 후 우리는 잠깐 이야기를 나눴어요.','chatted','A2','greeting',1,'two people talking casual chat'),
('w_greeting_A2_11','meeting','/ˈmiːtɪŋ/','noun','만남, 회의','An occasion when people come together.','Our first {meeting} was quite memorable.','우리의 첫 만남은 꽤 기억에 남아요.','meeting','A2','greeting',1,'first meeting memorable impression'),
('w_greeting_A2_12','introduce yourself','/ˌɪntrəˈdjuːs jɔːˈsɛlf/','phrase','자기소개하다','To present yourself to others by saying your name and details.','Please {introduce yourself} to the group.','그룹에 자기소개를 해주세요.','introduce yourself','A2','greeting',1,'group introduction presentation people'),
('w_greeting_A2_13','long time','/lɒŋ taɪm/','phrase','오랫동안','A phrase used to say you have not seen someone in a while.','It''s been a {long time} since we last met!','마지막으로 만난 지 오래됐네요!','long time','A2','greeting',1,'reunion old friends surprise'),
('w_greeting_A2_14','pleased','/pliːzd/','adjective','기쁜, 반가운','Feeling happy about something.','I''m very {pleased} to meet you all.','모두 만나게 되어 정말 반가워요.','pleased','A2','greeting',1,'pleased happy group introduction'),
('w_greeting_A2_15','shake hands','/ʃeɪk hændz/','phrase','악수하다','To grasp and move someone''s hand as a greeting.','They {shook hands} and smiled warmly.','그들은 악수를 하고 따뜻하게 미소를 지었어요.','shook hands','A2','greeting',1,'handshake smile warm business'),
('w_greeting_A2_16','see you','/siː juː/','phrase','나중에 봐요','An informal farewell.','"{See you} tomorrow!" she called out.','내일 봐요! 라고 그녀가 불렀어요.','See you','A2','greeting',1,'waving departure see again'),
('w_greeting_A2_17','take care','/teɪk kɛr/','phrase','잘 지내요, 조심히 가요','Said when parting to wish someone well.','"{Take care}!" he said with a wave.','잘 지내요! 라고 그가 손을 흔들며 말했어요.','Take care','A2','greeting',1,'caring farewell warm goodbye'),
('w_greeting_A2_18','come from','/kʌm frʌm/','phrase','~출신이에요','To indicate where one was born or raised.','I {come from} Busan originally.','저는 원래 부산 출신이에요.','come from','A2','greeting',2,'map hometown origin background'),
('w_greeting_A2_19','work as','/wɜːrk æz/','phrase','~으로 일하다','To describe one''s occupation.','I {work as} a graphic designer.','저는 그래픽 디자이너로 일해요.','work as','A2','greeting',2,'job occupation introduction work'),
('w_greeting_A2_20','live in','/lɪv ɪn/','phrase','~에 살아요','To indicate where one resides.','I {live in} Seoul with my family.','저는 가족과 함께 서울에 살아요.','live in','A2','greeting',2,'city home residence location'),
('w_greeting_A2_21','pleasure','/ˈplɛʒər/','noun','기쁨, 영광','A feeling of satisfaction or enjoyment.','It''s a {pleasure} to meet you at last.','드디어 만나게 되어 영광이에요.','pleasure','A2','greeting',1,'formal pleasure honor meeting'),
('w_greeting_A2_22','too','/tuː/','adverb','~도, 마찬가지로','Also;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_greeting_B1_01','acquaintance','/əˈkweɪntəns/','noun','지인, 아는 사람','A person you know but are not close friends with.','She is a business {acquaintance} I met at a conference.','그녀는 컨퍼런스에서 만난 비즈니스 지인이에요.','acquaintance','B1','greeting',2,'business conference networking meet'),
('w_greeting_B1_02','impression','/ɪmˈprɛʃən/','noun','인상, 첫인상','An idea or feeling about someone or something.','He made a wonderful first {impression} at the interview.','그는 면접에서 훌륭한 첫인상을 남겼어요.','impression','B1','greeting',2,'first impression interview confident'),
('w_greeting_B1_03','networking','/ˈnɛtwɜːrkɪŋ/','noun','네트워킹, 인맥 쌓기','Interacting with others to exchange information and develop contacts.','Active {networking} helped her find a new job.','적극적인 네트워킹이 그녀가 새 직장을 찾는 데 도움이 됐어요.','networking','B1','greeting',2,'networking event business cards'),
('w_greeting_B1_04','courtesy','/ˈkɜːrtɪsi/','noun','예의, 공손함','Polite behavior that shows respect.','He greeted everyone with {courtesy} and warmth.','그는 예의와 따뜻함으로 모든 사람에게 인사했어요.','courtesy','B1','greeting',2,'polite respectful warm greeting'),
('w_greeting_B1_05','rapport','/ræˈpɔːr/','noun','유대감, 친밀감','A close and harmonious relationship.','They quickly built a good {rapport} over coffee.','그들은 커피를 마시며 금세 유대감을 쌓았어요.','rapport','B1','greeting',2,'connection rapport coffee meeting'),
('w_greeting_B1_06','icebreaker','/ˈaɪsˌbreɪkər/','noun','분위기 풀기, 아이스브레이커','An activity or question to ease social tension.','The trainer used a fun {icebreaker} to start the session.','강사는 재미있는 아이스브레이커로 세션을 시작했어요.','icebreaker','B1','greeting',3,'group activity icebreaker fun'),
('w_greeting_B1_07','compliment','/ˈkɒmplɪmənt/','noun','칭찬','A polite expression of praise.','He opened the conversation with a sincere {compliment}.','그는 진심 어린 칭찬으로 대화를 시작했어요.','compliment','B1','greeting',2,'compliment smile praise genuine'),
('w_greeting_B1_08','reception','/rɪˈsɛpʃən/','noun','환영 행사, 리셉션','A formal social occasion to welcome guests.','They met at the company {reception} event.','그들은 회사 환영 행사에서 만났어요.','reception','B1','greeting',3,'reception event formal gathering'),
('w_greeting_B1_09','hospitality','/ˌhɒspɪˈtæləti/','noun','환대, 대접','The friendly and generous reception of guests.','Korean {hospitality} is known around the world.','한국의 환대는 전 세계에 알려져 있어요.','hospitality','B1','greeting',3,'warm hospitality hosting guests'),
('w_greeting_B1_10','mutual','/ˈmjuːtʃuəl/','adjective','서로의, 공통의','Shared by two or more people equally.','We have several {mutual} friends, I think.','우리에게 공통 친구가 몇 명 있는 것 같아요.','mutual','B1','greeting',2,'mutual friends connection network'),
('w_greeting_B1_11','approach','/əˈproʊtʃ/','verb','다가가다, 접근하다','To go near or closer to someone.','She {approached} the newcomer with a warm smile.','그녀는 따뜻한 미소로 신입에게 다가갔어요.','approached','B1','greeting',2,'approaching stranger smile open'),
('w_greeting_B1_12','conversation','/ˌkɒnvərˈseɪʃən/','noun','대화','A talk between two or more people.','They struck up a {conversation} at the event.','그들은 행사에서 대화를 나누기 시작했어요.','conversation','B1','greeting',2,'two people talking event'),
('w_greeting_B1_13','exchange','/ɪksˈtʃeɪndʒ/','verb','교환하다','To give something and receive something in return.','They {exchanged} business cards after the meeting.','회의 후 그들은 명함을 교환했어요.','exchanged','B1','greeting',2,'business cards exchange networking'),
('w_greeting_B1_14','background','/ˈbækɡraʊnd/','noun','배경, 출신','A person''s past experience and origin.','Can you tell me a bit about your {background}?','배경에 대해 조금 말씀해 주실 수 있나요?','background','B1','greeting',2,'background profile introduction'),
('w_greeting_B1_15','reconnect','/ˌriːkəˈnɛkt/','verb','다시 연락하다, 재회하다','To establish contact again after a period of separation.','It was great to {reconnect} with old classmates.','예전 동급생들과 다시 연락이 닿아서 정말 좋았어요.','reconnect','B1','greeting',2,'reunion classmates reconnect happy'),
('w_greeting_B1_16','gesture','/ˈdʒɛstʃər/','noun','몸짓, 제스처','A movement of the body used to express a feeling.','A simple {gesture} like a nod can go a long way.','고개를 끄덕이는 간단한 제스처도 큰 의미가 있어요.','gesture','B1','greeting',2,'body language nod gesture polite'),
('w_greeting_B1_17','bond','/bɒnd/','noun','유대, 끈','A close connection between people.','They formed a quick {bond} over shared interests.','공통 관심사로 금세 유대를 형성했어요.','bond','B1','greeting',2,'friendship bond connection share'),
('w_greeting_B1_18','recognition','/ˌrɛkəɡˈnɪʃən/','noun','알아봄, 인식','The action of identifying someone you know.','There was instant {recognition} when they made eye contact.','눈이 마주치자 바로 알아봤어요.','recognition','B1','greeting',3,'recognition eye contact familiar'),
('w_greeting_B1_19','relationship','/rɪˈleɪʃənʃɪp/','noun','관계','The way two or more people are connected.','Building a good {relationship} starts with a warm greeting.','좋은 관계 형성은 따뜻한 인사에서 시작돼요.','relationship','B1','greeting',2,'relationship building connection'),
('w_greeting_B1_20','colleague','/ˈkɒliːɡ/','noun','동료','A person you work with professionally.','Let me introduce you to my {colleague} from marketing.','마케팅 부서 동료를 소개해 드릴게요.','colleague','B1','greeting',2,'office colleague introduction'),
('w_greeting_B1_21','common ground','/ˈkɒmən ɡraʊnd/','phrase','공통점','A shared interest or area of agreement.','They quickly found {common ground} in their love of hiking.','그들은 하이킹을 좋아한다는 공통점을 금세 찾았어요.','common ground','B1','greeting',2,'finding common ground shared interest'),
('w_greeting_B1_22','reunion','/ˌriːˈjuːniən/','noun','재회, 동창회','A social gathering of people who have been apart.','The school {reunion} was full of warm greetings.','학교 동창회는 따뜻한 인사로 가득했어요.','reunion','B1','greeting',2,'reunion party classmates warm'),
('w_greeting_B1_23','outgoing','/ˈaʊtˌɡoʊɪŋ/','adjective','외향적인','Friendly and confident in social situations.','She is very {outgoing} and greets everyone easily.','그녀는 매우 외향적이어서 누구에게나 쉽게 인사해요.','outgoing','B1','greeting',2,'outgoing social person friendly'),
('w_greeting_B1_24','first name','/fɜːrst neɪm/','noun','이름 (성이 아닌 개인 이름)','The given name, as opposed to surname.','Please feel free to use my {first name}.','제 이름을 편하게 불러주세요.','first name','B1','greeting',2,'name informal first name basis'),
('w_greeting_B1_25','atmosphere','/ˈætməsfɪr/','noun','분위기','The mood or feeling of a place or social situation.','The {atmosphere} at the party was very welcoming.','파티 분위기가 매우 환영하는 느낌이었어요.','atmosphere','B1','greeting',2,'party atmosphere welcoming warm'),
('w_greeting_B1_26','genuine','/ˈdʒɛnjuɪn/','adjective','진심 어린, 진정한','Truly sincere and authentic.','A {genuine} smile is the best greeting of all.','진심 어린 미소가 가장 좋은 인사예요.','genuine','B1','greeting',2,'genuine smile authentic warm'),
('w_greeting_B1_27','respectful','/rɪˈspɛktfəl/','adjective','존중하는, 예의 있는','Showing consideration and esteem.','It''s important to be {respectful} when greeting elders.','어른께 인사할 때는 예의 있게 대하는 것이 중요해요.','respectful','B1','greeting',2,'respect elders bow polite'),
('w_greeting_B1_28','warmth','/wɔːrmθ/','noun','따뜻함','A quality of being kind and friendly.','Her {warmth} made everyone feel immediately at ease.','그녀의 따뜻함으로 모든 사람이 바로 편안함을 느꼈어요.','warmth','B1','greeting',2,'warm person kind smile ease'),
('w_greeting_B1_29','mention','/ˈmɛnʃən/','verb','언급하다','To refer to something briefly.','He {mentioned} that we had a mutual friend.','그는 우리에게 공통 친구가 있다고 언급했어요.','mentioned','B1','greeting',2,'mention conversation mutual friend'),
('w_greeting_B1_30','occasion','/əˈkeɪʒən/','noun','경우, 자리','A particular time or event.','I met her on a formal {occasion} last spring.','지난 봄 격식 있는 자리에서 그녀를 만났어요.','occasion','B1','greeting',3,'formal occasion event spring'),
('w_greeting_B1_31','industry','/ˈɪndəstri/','noun','업계, 산업','A particular branch of trade or production.','I noticed you also work in the tech {industry}.','기술 업계에서도 일하고 계시는군요.','industry','B1','greeting',2,'tech industry networking business'),
('w_greeting_B1_32','contact','/ˈkɒntækt/','noun','연락처, 연락','Communication with someone;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_greeting_B2_01','etiquette','/ˈɛtɪkɛt/','noun','예절, 에티켓','The conventional requirements of social behavior.','Business {etiquette} varies greatly between cultures.','비즈니스 예절은 문화마다 크게 달라요.','etiquette','B2','greeting',2,'business etiquette culture rules'),
('w_greeting_B2_02','demeanor','/dɪˈmiːnər/','noun','태도, 몸가짐','Outward behavior or bearing in social situations.','His calm {demeanor} put everyone at ease immediately.','그의 차분한 태도로 모두가 바로 편안해졌어요.','demeanor','B2','greeting',3,'calm demeanor composed professional'),
('w_greeting_B2_03','decorum','/dɪˈkɔːrəm/','noun','예의범절, 단정함','Behavior in keeping with good taste and propriety.','She maintained perfect {decorum} at the formal reception.','그녀는 격식 있는 리셉션에서 완벽한 예의범절을 지켰어요.','decorum','B2','greeting',3,'formal reception proper decorum'),
('w_greeting_B2_04','salutation','/ˌsæljʊˈteɪʃən/','noun','인사말, 경례','A gesture or expression made as a greeting.','He gave a slight bow as a {salutation}.','그는 가볍게 고개를 숙여 인사했어요.','salutation','B2','greeting',3,'bow salutation formal greeting'),
('w_greeting_B2_05','approachable','/əˈproʊtʃəbl/','adjective','다가가기 쉬운, 친근한','Friendly and easy to talk to.','Her {approachable} manner made networking feel effortless.','그녀의 친근한 태도로 네트워킹이 자연스럽게 느껴졌어요.','approachable','B2','greeting',2,'approachable friendly open body language'),
('w_greeting_B2_06','diplomatic','/ˌdɪpləˈmætɪk/','adjective','외교적인, 요령 있는','Having the ability to deal with people tactfully.','She was {diplomatic} in how she handled introductions.','그녀는 소개를 처리하는 방식이 외교적이었어요.','diplomatic','B2','greeting',2,'diplomatic tactful professional'),
('w_greeting_B2_07','tactful','/ˈtæktfəl/','adjective','요령 있는, 눈치 있는','Having skill in saying the right thing at the right time.','A {tactful} greeting can open many doors.','요령 있는 인사는 많은 기회의 문을 열 수 있어요.','tactful','B2','greeting',2,'tactful conversation social skill'),
('w_greeting_B2_08','endearing','/ɪnˈdɪərɪŋ/','adjective','정겨운, 마음을 끄는','Inspiring affection or warmth.','His {endearing} way of saying hello made him unforgettable.','그가 인사하는 정겨운 방식 덕분에 그를 잊을 수 없어요.','endearing','B2','greeting',3,'endearing charm warm memorable'),
('w_greeting_B2_09','charismatic','/ˌkærɪzˈmætɪk/','adjective','카리스마 있는','Having a natural ability to attract and inspire people.','Her {charismatic} entrance drew everyone''s attention.','그녀의 카리스마 넘치는 등장이 모든 이의 시선을 끌었어요.','charismatic','B2','greeting',3,'charismatic confident leader attention'),
('w_greeting_B2_10','congenial','/kənˈdʒiːniəl/','adjective','마음이 맞는, 유쾌한','Pleasant because of a personality that suits you.','The {congenial} atmosphere made introductions easy.','마음이 맞는 분위기 덕분에 소개가 수월했어요.','congenial','B2','greeting',3,'congenial warm group atmosphere'),
('w_greeting_B2_11','articulate','/ɑːrˈtɪkjʊlɪt/','adjective','표현이 명확한','Able to express ideas fluently and clearly.','He was very {articulate} during the self-introduction.','그는 자기소개 중에 표현이 매우 명확했어요.','articulate','B2','greeting',3,'articulate speech clear confident'),
('w_greeting_B2_12','composure','/kəmˈpoʊʒər/','noun','침착함, 자제력','The state of being calm and in control.','She maintained her {composure} despite the large audience.','많은 청중 앞에서도 그녀는 침착함을 유지했어요.','composure','B2','greeting',3,'calm composure audience speaking'),
('w_greeting_B2_13','protocol','/ˈproʊtəkɒl/','noun','의전, 규칙','The official procedure or etiquette in a formal situation.','Business card exchange follows a strict {protocol} in Korea.','한국에서 명함 교환은 엄격한 의전을 따라요.','protocol','B2','greeting',2,'business protocol formal Korea'),
('w_greeting_B2_14','reciprocate','/rɪˈsɪprəkeɪt/','verb','화답하다, 보답하다','To respond to a gesture by making a similar one.','He smiled, and she {reciprocated} warmly.','그가 미소 짓자 그녀도 따뜻하게 화답했어요.','reciprocated','B2','greeting',3,'reciprocate smile mutual gesture'),
('w_greeting_B2_15','poise','/pɔɪz/','noun','품위, 자신감 있는 태도','Graceful and elegant bearing in a social setting.','She greeted the delegates with remarkable {poise}.','그녀는 대표단을 놀라운 품위로 맞이했어요.','poise','B2','greeting',3,'poise elegant confident posture'),
('w_greeting_B2_16','cultivate','/ˈkʌltɪveɪt/','verb','(관계를) 쌓다, 키우다','To develop or maintain a relationship over time.','She knew how to {cultivate} professional relationships.','그녀는 전문적인 관계를 쌓는 방법을 알고 있었어요.','cultivate','B2','greeting',3,'relationship building professional'),
('w_greeting_B2_17','brevity','/ˈbrɛvɪti/','noun','간결함','Concise and exact use of words in speech.','The art of greeting lies in {brevity} and sincerity.','인사의 예술은 간결함과 진심에 있어요.','brevity','B2','greeting',3,'concise speech effective brief'),
('w_greeting_B2_18','distinction','/dɪˈstɪŋkʃən/','noun','구별, 품격','A notable quality or characteristic.','She greeted guests with a sense of {distinction}.','그녀는 품격 있게 손님을 맞이했어요.','distinction','B2','greeting',3,'distinction class elegance greeting'),
('w_greeting_B2_19','acknowledge','/əkˈnɒlɪdʒ/','verb','알아보다, 인정하다','To recognize the presence or importance of someone.','He {acknowledged} everyone with a nod as he entered.','그는 입장하면서 고개를 끄덕여 모두를 알아봤어요.','acknowledged','B2','greeting',2,'acknowledge nod professional'),
('w_greeting_B2_20','personable','/ˈpɜːrsənəbl/','adjective','붙임성 있는, 호감 가는','Having a pleasant manner and appearance.','A {personable} greeting sets the tone for any relationship.','호감 가는 인사는 모든 관계의 분위기를 결정해요.','personable','B2','greeting',2,'personable friendly first impression'),
('w_greeting_B2_21','convey','/kənˈveɪ/','verb','전달하다, 전하다','To communicate or express a feeling or idea.','A simple greeting can {convey} genuine respect.','간단한 인사로 진심 어린 존중을 전달할 수 있어요.','convey','B2','greeting',2,'convey message expression respect'),
('w_greeting_B2_22','formality','/fɔːrˈmæləti/','noun','형식, 격식','The quality of being formal or ceremonious.','Korean business greetings often involve a degree of {formality}.','한국 비즈니스 인사에는 어느 정도의 격식이 포함돼요.','formality','B2','greeting',2,'formality business Korean culture'),
('w_greeting_B2_23','engaging','/ɪnˈɡeɪdʒɪŋ/','adjective','매력적인, 흥미를 끄는','Charming and attracting favorable attention.','Her {engaging} personality made her popular at events.','그녀의 매력적인 성격 덕분에 행사에서 인기가 많았어요.','engaging','B2','greeting',2,'engaging personality charming event'),
('w_greeting_B2_24','demystify','/diːˈmɪstɪfaɪ/','verb','쉽게 풀어주다, 신비를 제거하다','To make something easier to understand.','Cross-cultural training can {demystify} greeting norms.','문화 간 훈련은 인사 규범을 쉽게 이해할 수 있게 해줘요.','demystify','B2','greeting',4,'cross cultural training understand'),
('w_greeting_B2_25','nuance','/ˈnjuːɑːns/','noun','뉘앙스, 미묘한 차이','A subtle distinction in meaning or expression.','There are many {nuances} in how Koreans greet elders.','한국인이 어른께 인사하는 방식에는 많은 뉘앙스가 있어요.','nuances','B2','greeting',2,'nuance culture subtle difference'),
('w_greeting_B2_26','amiable','/ˈeɪmiəbl/','adjective','상냥한, 붙임성 있는','Having a friendly and pleasant manner.','His {amiable} greeting put the new hire at ease.','그의 상냥한 인사 덕분에 신입 사원이 편안해졌어요.','amiable','B2','greeting',2,'amiable friendly new hire ease'),
('w_greeting_B2_27','reserved','/rɪˈzɜːrvd/','adjective','내성적인, 말이 없는','Slow to reveal emotions or opinions.','She seemed {reserved} at first but warmed up quickly.','그녀는 처음에는 내성적인 것 같았지만 금방 마음을 열었어요.','reserved','B2','greeting',2,'reserved shy warm up meeting'),
('w_greeting_B2_28','initiative','/ɪˈnɪʃɪətɪv/','noun','주도, 솔선','The ability to take charge and start something.','He took the {initiative} and introduced himself first.','그는 솔선하여 먼저 자기소개를 했어요.','initiative','B2','greeting',2,'initiative first step introduce leadership'),
('w_greeting_B2_29','forthcoming','/ˌfɔːrθˈkʌmɪŋ/','adjective','기꺼이 말하는, 솔직한','Willing to give information or to be helpful.','She was {forthcoming} about her background.','그녀는 자신의 배경에 대해 기꺼이 이야기했어요.','forthcoming','B2','greeting',3,'open forthcoming talkative introduction'),
('w_greeting_B2_30','convivial','/kənˈvɪviəl/','adjective','유쾌한, 친목적인','Friendly and lively, relating to a social gathering.','The {convivial} atmosphere encouraged everyone to mingle.','유쾌한 분위기가 모두를 어울리게 했어요.','convivial','B2','greeting',3,'convivial party mingle social'),
('w_greeting_B2_31','inclusive','/ɪnˈkluːsɪv/','adjective','포용적인, 모두를 포함하는','Including all members or aspects without exclusion.','An {inclusive} greeting acknowledges everyone in the room.','포용적인 인사는 자리에 있는 모두를 알아봐요.','inclusive','B2','greeting',2,'inclusive all welcome group'),
('w_greeting_B2_32','demeanor','/dɪˈmiːnər/','noun','태도, 품행','The way someone behaves or looks outwardly.','A confident {demeanor} signals that you are comfortable.','자신감 있는 태도는 편안함을 나타내요.','demeanor','B2','greeting',3,'confident demeanor posture body language'),
('w_greeting_B2_33','captivating','/ˈkæptɪveɪtɪŋ/','adjective','매혹적인, 시선을 끄는','Attracting and holding interest in a charming way.','Her {captivating} introduction caught the whole room''s attention.','그녀의 매혹적인 소개로 방 전체의 관심이 쏠렸어요.','captivating','B2','greeting',3,'captivating attention room charm'),
('w_greeting_B2_34','benchmark','/ˈbɛntʃmɑːrk/','noun','기준, 벤치마크','A standard or point of reference.','His greeting style became the {benchmark} for the team.','그의 인사 방식이 팀의 기준이 되었어요.','benchmark','B2','greeting',4,'standard benchmark team professional'),
('w_greeting_B2_35','establish','/ɪˈstæblɪʃ/','verb','수립하다, 확립하다','To set up or bring about something lasting.','A warm greeting helps {establish} trust from the start.','따뜻한 인사는 처음부터 신뢰를 쌓는 데 도움이 돼요.','establish','B2','greeting',2,'trust build establish relationship');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_greeting_C1_01','eloquent','/ˈɛləkwənt/','adjective','웅변적인, 표현이 뛰어난','Fluent or persuasive in speaking or writing.','His {eloquent} introduction impressed the entire board.','그의 뛰어난 소개가 이사회 전체를 감동시켰어요.','eloquent','C1','greeting',3,'eloquent speech impressive board'),
('w_greeting_C1_02','distinguished','/dɪˈstɪŋɡwɪʃt/','adjective','저명한, 탁월한','Successful, authoritative, and commanding great respect.','The {distinguished} guest was greeted with a standing ovation.','저명한 손님은 기립 박수로 맞이받았어요.','distinguished','C1','greeting',4,'distinguished guest honor ceremony'),
('w_greeting_C1_03','poised','/pɔɪzd/','adjective','침착한, 품위 있는','Having a graceful and composed manner.','She looked {poised} and confident as she greeted the crowd.','그녀는 군중에게 인사하며 침착하고 자신감 있게 보였어요.','poised','C1','greeting',3,'poised confident crowd greeting'),
('w_greeting_C1_04','affable','/ˈæfəbl/','adjective','상냥한, 붙임성 있는','Friendly, good-natured, and easy to talk to.','His {affable} manner made him beloved by everyone he met.','그의 상냥한 태도로 만나는 모든 사람에게 사랑받았어요.','affable','C1','greeting',3,'affable friendly loved warm'),
('w_greeting_C1_05','gregarious','/ɡrɪˈɡɛəriəs/','adjective','사교적인, 군집을 좋아하는','Fond of company;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_greeting_C2_01','urbane','/ɜːrˈbeɪn/','adjective','세련된, 도시적인','Courteous and refined in manner.','His {urbane} greeting set the tone for the entire evening.','그의 세련된 인사가 저녁 내내 분위기를 결정했어요.','urbane','C2','greeting',4,'urbane sophisticated evening tone'),
('w_greeting_C2_02','debonair','/ˌdɛbəˈnɛr/','adjective','우아한, 세련된','Confident, stylish, and charming.','He walked in with a {debonair} greeting for each guest.','그는 각 손님에게 우아하게 인사하며 입장했어요.','debonair','C2','greeting',4,'debonair charming confident guest'),
('w_greeting_C2_03','refined','/rɪˈfaɪnd/','adjective','품위 있는, 세련된','Elegant and cultured in taste and manner.','Her {refined} manners were evident from the first greeting.','첫 인사부터 그녀의 품위 있는 태도가 분명했어요.','refined','C2','greeting',3,'refined elegant manners first'),
('w_greeting_C2_04','gracious','/ˈɡreɪʃəs/','adjective','우아한, 품위 있는','Courteous, kind, and pleasant.','She was {gracious} in receiving guests from all walks of life.','그녀는 각계각층의 손님을 품위 있게 맞이했어요.','gracious','C2','greeting',3,'gracious host all walks'),
('w_greeting_C2_05','ceremonious','/ˌsɛrɪˈmoʊniəs/','adjective','예식적인, 의례적인','Relating to or appropriate for ceremonies.','The state dinner began with a {ceremonious} round of introductions.','국빈 만찬은 의례적인 소개 순서로 시작되었어요.','ceremonious','C2','greeting',4,'state dinner ceremonious introductions'),
('w_greeting_C2_06','magnanimous','/mæɡˈnænɪməs/','adjective','관대한, 도량이 넓은','Generous and forgiving, especially to enemies.','His {magnanimous} greeting after the dispute restored goodwill.','분쟁 후 그의 관대한 인사로 친선이 회복되었어요.','magnanimous','C2','greeting',4,'generous dispute goodwill restore'),
('w_greeting_C2_07','venerable','/ˈvɛnərəbl/','adjective','존경받는, 노숙한','Accorded a great deal of respect, especially due to age.','The {venerable} professor was greeted with deep bows.','존경받는 교수님은 깊은 인사로 맞이받았어요.','venerable','C2','greeting',4,'professor respected deep bow'),
('w_greeting_C2_08','decorum','/dɪˈkɔːrəm/','noun','예의범절, 단정함','Behavior in keeping with good taste and propriety.','State functions demand absolute {decorum} in greetings.','국가 행사는 인사에서 완벽한 예의범절을 요구해요.','decorum','C2','greeting',3,'state function absolute proper'),
('w_greeting_C2_09','protocol','/ˈproʊtəkɒl/','noun','의전, 프로토콜','The established rules of correct conduct in formal situations.','Diplomatic {protocol} governs how leaders greet one another.','외교 의전은 지도자들이 서로 인사하는 방법을 규정해요.','protocol','C2','greeting',3,'diplomatic protocol leaders rules'),
('w_greeting_C2_10','ambassador','/æmˈbæsədər/','noun','대사, 사절','An accredited diplomat sent to represent a country.','The {ambassador} extended a warm greeting to the delegation.','대사는 대표단에게 따뜻한 인사를 건넸어요.','ambassador','C2','greeting',4,'ambassador delegation formal greeting'),
('w_greeting_C2_11','felicitate','/fɪˈlɪsɪteɪt/','verb','축하하다, 경하하다','To congratulate or express goodwill.','He rose to {felicitate} the newly appointed director.','그는 새로 임명된 이사를 축하하기 위해 일어났어요.','felicitate','C2','greeting',5,'congratulate director appointed formal'),
('w_greeting_C2_12','salutation','/ˌsæljʊˈteɪʃən/','noun','경례, 인사','A gesture of respect or polite greeting.','Letters to dignitaries begin with a formal {salutation}.','고위직 인사에게 보내는 편지는 격식 있는 인사로 시작해요.','salutation','C2','greeting',3,'formal letter dignitary salutation'),
('w_greeting_C2_13','obeisance','/oʊˈbeɪsəns/','noun','절, 경의의 몸짓','A gesture showing submission or respect.','The courtiers made deep {obeisance} upon the monarch''s arrival.','군주가 도착하자 신하들은 깊이 절했어요.','obeisance','C2','greeting',5,'bow monarch deep respect court'),
('w_greeting_C2_14','convocation','/ˌkɒnvəˈkeɪʃən/','noun','소집, 졸업식','A large formal assembly of people.','The chancellor greeted graduates at the {convocation} ceremony.','총장은 졸업식에서 졸업생들에게 인사했어요.','convocation','C2','greeting',5,'graduation ceremony chancellor formal'),
('w_greeting_C2_15','benevolence','/bɪˈnɛvələns/','noun','자선, 선의','The quality of being well-meaning and generous.','His greeting radiated {benevolence} and genuine care.','그의 인사에서는 선의와 진심 어린 관심이 넘쳐났어요.','benevolence','C2','greeting',4,'benevolence goodwill genuine care'),
('w_greeting_C2_16','approbation','/ˌæprəˈbeɪʃən/','noun','승인, 칭찬','Approval or praise, especially from an authority.','Her warm greeting earned the {approbation} of the senior staff.','그녀의 따뜻한 인사는 선임 직원들의 칭찬을 받았어요.','approbation','C2','greeting',5,'approval senior staff praise'),
('w_greeting_C2_17','hauteur','/hoʊˈtɜːr/','noun','거만함, 오만한 태도','An air of condescension or arrogance.','He greeted visitors without any trace of {hauteur}.','그는 어떤 오만한 태도도 없이 방문객을 맞이했어요.','hauteur','C2','greeting',5,'arrogance without humble genuine'),
('w_greeting_C2_18','intercession','/ˌɪntərˈsɛʃən/','noun','중재, 탄원','The action of intervening on behalf of another.','Her warm {intercession} brought two rival parties together.','그녀의 따뜻한 중재로 두 경쟁 측이 하나가 되었어요.','intercession','C2','greeting',5,'mediation bring together rival'),
('w_greeting_C2_19','panache','/pəˈnæʃ/','noun','기개, 화려한 스타일','A confidence and flamboyant style.','He greeted the audience with great {panache}.','그는 훌륭한 기개로 청중에게 인사했어요.','panache','C2','greeting',4,'style flair confidence audience'),
('w_greeting_C2_20','suzerainty','/ˈsjuːzərənti/','noun','종주권, 최고 권위','Authority over another state while allowing internal autonomy.','The emissary greeted under the banner of {suzerainty}.','사절은 종주권의 깃발 아래에서 인사했어요.','suzerainty','C2','greeting',5,'authority emissary formal historical'),
('w_greeting_C2_21','gravitas','/ˈɡrævɪtæs/','noun','무게감, 위엄','Dignity, seriousness, or solemnity of manner.','Her {gravitas} was evident from the moment she said hello.','그녀는 인사하는 순간부터 위엄이 느껴졌어요.','gravitas','C2','greeting',4,'gravitas dignity serious manner'),
('w_greeting_C2_22','sagacious','/səˈɡeɪʃəs/','adjective','현명한, 총명한','Having or showing keen mental discernment.','A {sagacious} diplomat knows when a simple nod suffices.','현명한 외교관은 간단한 고개 끄덕임으로 충분한 때를 알아요.','sagacious','C2','greeting',5,'wise diplomat nod subtle'),
('w_greeting_C2_23','felicitous','/fɪˈlɪsɪtəs/','adjective','적절한, 기분 좋은','Well-chosen or suited to the circumstances.','His {felicitous} opening words set a perfect tone.','그의 적절한 첫마디가 완벽한 분위기를 만들었어요.','felicitous','C2','greeting',4,'well chosen opening words tone'),
('w_greeting_C2_24','bespoke','/bɪˈspoʊk/','adjective','맞춤의, 개인화된','Made for a particular person or purpose.','Each guest received a {bespoke} written greeting card.','각 손님은 개인화된 친필 인사 카드를 받았어요.','bespoke','C2','greeting',4,'personalized custom card individual'),
('w_greeting_C2_25','salute','/səˈluːt/','verb','경례하다, 존경을 표하다','To greet with a gesture of respect.','The officer {saluted} smartly upon recognizing the general.','장교는 장군을 알아보고 단호하게 경례했어요.','saluted','C2','greeting',3,'salute officer military respect'),
('w_greeting_C2_26','benediction','/ˌbɛnɪˈdɪkʃən/','noun','축복, 축도','A blessing spoken at the end of a meeting or ceremony.','The ceremony closed with a warm {benediction}.','행사는 따뜻한 축복으로 마무리되었어요.','benediction','C2','greeting',5,'blessing ceremony close formal'),
('w_greeting_C2_27','intercultural','/ˌɪntərˈkʌltʃərəl/','adjective','이문화 간의','Relating to communication between different cultures.','She specializes in {intercultural} greeting etiquette.','그녀는 이문화 간 인사 예절을 전문으로 해요.','intercultural','C2','greeting',4,'cross cultural etiquette specialist'),
('w_greeting_C2_28','parting','/ˈpɑːrtɪŋ/','noun','작별, 이별','The action of leaving or separating.','His {parting} words left a lasting impression on everyone.','그의 작별 인사는 모든 사람에게 오래도록 남았어요.','parting','C2','greeting',3,'farewell last words impression'),
('w_greeting_C2_29','quintessential','/ˌkwɪntɪˈsɛnʃəl/','adjective','전형적인, 정수의','Representing the most perfect example of a quality.','His bow was the {quintessential} Korean greeting.','그의 절은 전형적인 한국식 인사였어요.','quintessential','C2','greeting',4,'perfect bow Korean traditional'),
('w_greeting_C2_30','gravely','/ˈɡreɪvli/','adverb','엄숙하게, 진지하게','In a serious or solemn manner.','He {gravely} acknowledged the delegation''s presence.','그는 엄숙하게 대표단의 존재를 알아봤어요.','gravely','C2','greeting',5,'solemn serious acknowledge formal'),
('w_greeting_C2_31','obsequious','/əbˈsiːkwiəs/','adjective','굽신거리는, 비굴한','Excessively eager to please or serve.','He avoided {obsequious} behavior when greeting his superiors.','그는 상사에게 인사할 때 굽신거리는 행동을 피했어요.','obsequious','C2','greeting',5,'sycophantic avoid superiors proper'),
('w_greeting_C2_32','sanguine','/ˈsæŋɡwɪn/','adjective','낙관적인, 쾌활한','Optimistic, especially in difficult situations.','He remained {sanguine} and welcoming despite the tension.','긴장감 속에서도 그는 낙관적이고 환영하는 태도를 유지했어요.','sanguine','C2','greeting',4,'optimistic welcoming despite tension'),
('w_greeting_C2_33','propitious','/prəˈpɪʃəs/','adjective','상서로운, 좋은 징조의','Giving or indicating a good chance of success.','They chose a {propitious} moment to make introductions.','그들은 상서로운 순간을 골라 소개를 했어요.','propitious','C2','greeting',5,'auspicious timing good moment'),
('w_greeting_C2_34','discernment','/dɪˈsɜːrnmənt/','noun','통찰력, 안목','The ability to judge well.','Social {discernment} tells you when formality is required.','사회적 안목은 격식이 필요한 때를 알려줘요.','discernment','C2','greeting',4,'judgment social situation formal'),
('w_greeting_C2_35','ineffable','/ɪˈnɛfəbl/','adjective','말로 표현할 수 없는','Too great or extreme to be expressed in words.','There was something {ineffable} in the way she greeted the crowd.','그녀가 군중에게 인사하는 방식에는 말로 표현할 수 없는 무언가가 있었어요.','ineffable','C2','greeting',5,'indescribable quality greeting crowd');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_emotion_A1_01','happy','/ˈhæpi/','adjective','행복한','Feeling or showing pleasure and contentment.','She was {happy} to see her friend.','그녀는 친구를 보고 행복했어요.','happy','A1','emotion',1,'happy smiling person joyful'),
('w_emotion_A1_02','sad','/sæd/','adjective','슬픈','Feeling or causing sorrow or unhappiness.','He looked {sad} after hearing the news.','그는 소식을 듣고 슬퍼 보였어요.','sad','A1','emotion',1,'sad person unhappy downcast'),
('w_emotion_A1_03','angry','/ˈæŋɡri/','adjective','화난','Feeling strong displeasure or hostility.','She was {angry} because he was late.','그가 늦어서 그녀는 화가 났어요.','angry','A1','emotion',1,'angry person upset frustrated'),
('w_emotion_A1_04','tired','/ˈtaɪərd/','adjective','피곤한','In need of sleep or rest;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_emotion_A2_01','surprised','/sərˈpraɪzd/','adjective','놀란','Feeling or showing astonishment at something unexpected.','I was completely {surprised} by the gift.','선물에 완전히 놀랐어요.','surprised','A2','emotion',1,'person surprised unexpected gift reaction'),
('w_emotion_A2_02','worried','/ˈwʌrid/','adjective','걱정되는','Feeling anxious about actual or potential problems.','She looked {worried} about the test results.','그녀는 시험 결과에 대해 걱정스러워 보였어요.','worried','A2','emotion',1,'person worried anxious test results'),
('w_emotion_A2_03','bored','/bɔːrd/','adjective','지루한','Feeling weary and uninterested.','He was {bored} during the long meeting.','그는 긴 회의 동안 지루해했어요.','bored','A2','emotion',1,'person bored long meeting office'),
('w_emotion_A2_04','confused','/kənˈfjuːzd/','adjective','혼란스러운','Unable to think clearly;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_emotion_B1_01','frustrated','/ˈfrʌstreɪtɪd/','adjective','답답한, 좌절한','Feeling annoyed or upset due to inability to change or achieve something.','I get {frustrated} when the internet is slow.','인터넷이 느릴 때 답답해요.','frustrated','B1','emotion',1,'person frustrated slow internet laptop'),
('w_emotion_B1_02','relieved','/rɪˈliːvd/','adjective','안도한','No longer feeling anxious because a problem has been resolved.','I was so {relieved} when the surgery went well.','수술이 잘 돼서 정말 안도했어요.','relieved','B1','emotion',1,'person relieved hospital surgery recovery'),
('w_emotion_B1_03','anxious','/ˈæŋkʃəs/','adjective','불안한, 초조한','Experiencing worry, unease, or nervousness about something uncertain.','She felt {anxious} waiting for the interview results.','면접 결과를 기다리며 불안해했어요.','anxious','B1','emotion',1,'person anxious waiting results office'),
('w_emotion_B1_04','embarrassed','/ɪmˈbærəst/','adjective','당황한, 창피한','Feeling ashamed or self-conscious because of something awkward.','I was so {embarrassed} when I tripped in public.','공공장소에서 넘어져서 너무 창피했어요.','embarrassed','B1','emotion',1,'person embarrassed tripping public'),
('w_emotion_B1_05','overwhelmed','/ˌoʊvərˈwelmd/','adjective','압도된, 너무 힘든','Feeling completely overcome by too much at once.','I feel {overwhelmed} with all the deadlines.','마감이 너무 많아서 압도돼요.','overwhelmed','B1','emotion',1,'person overwhelmed deadlines stress work'),
('w_emotion_B1_06','content','/kənˈtent/','adjective','만족스러운','In a state of peaceful happiness and satisfaction.','She felt {content} with her simple lifestyle.','그녀는 단순한 삶에 만족감을 느꼈어요.','content','B1','emotion',1,'person content cozy home simple life'),
('w_emotion_B1_07','hopeful','/ˈhoʊpfəl/','adjective','희망에 찬','Feeling optimism about a future event or outcome.','We were {hopeful} about the new project.','새 프로젝트에 희망을 품었어요.','hopeful','B1','emotion',1,'person hopeful new project start sunrise'),
('w_emotion_B1_08','jealous','/ˈdʒeləs/','adjective','질투하는, 시기하는','Feeling or showing envy of someone''s possessions or advantages.','He felt {jealous} when she got the promotion.','그녀가 승진했을 때 그는 질투를 느꼈어요.','jealous','B1','emotion',2,'person jealous promotion work colleague'),
('w_emotion_B1_09','guilty','/ˈɡɪlti/','adjective','죄책감이 드는','Feeling responsible for doing something wrong.','She felt {guilty} for forgetting his birthday.','그의 생일을 잊어버린 것에 죄책감을 느꼈어요.','guilty','B1','emotion',1,'person guilty regret forgetting'),
('w_emotion_B1_10','enthusiastic','/ɪnˌθjuːziˈæstɪk/','adjective','열정적인, 열의 있는','Having or showing intense enjoyment or eagerness.','He was {enthusiastic} about learning Korean.','그는 한국어 배우는 것에 열정적이었어요.','enthusiastic','B1','emotion',1,'person enthusiastic learning studying happy'),
('w_emotion_B1_11','irritated','/ˈɪrɪteɪtɪd/','adjective','짜증난','Feeling mild anger;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_emotion_B2_01','melancholic','/ˌmelənˈkɒlɪk/','adjective','우울한, 침울한','Having a feeling of pensive sadness with no obvious cause.','She had a {melancholic} expression as she stared at the rain.','그녀는 빗속을 바라보며 침울한 표정을 지었어요.','melancholic','B2','emotion',1,'person melancholic rain window sad pensive'),
('w_emotion_B2_02','empathetic','/ˌempəˈθetɪk/','adjective','공감하는','Showing an ability to understand and share the feelings of another.','She is very {empathetic} toward people in difficult situations.','그녀는 힘든 상황에 있는 사람들에게 매우 공감해요.','empathetic','B2','emotion',1,'person empathetic listening compassion support'),
('w_emotion_B2_03','nostalgic','/nɒˈstældʒɪk/','adjective','향수를 느끼는','Experiencing a sentimental longing for the past.','I felt {nostalgic} listening to the old songs.','오래된 노래를 들으며 향수를 느꼈어요.','nostalgic','B2','emotion',1,'person nostalgic old music memories'),
('w_emotion_B2_04','apprehensive','/ˌæprɪˈhensɪv/','adjective','걱정되는, 불안한','Worried that something bad might happen.','She was {apprehensive} about meeting her partner''s parents.','파트너의 부모님을 만나는 것에 불안해했어요.','apprehensive','B2','emotion',1,'person apprehensive meeting nervous formal'),
('w_emotion_B2_05','exhilarated','/ɪɡˈzɪləreɪtɪd/','adjective','활기에 넘치는, 신나는','Feeling very happy, animated, or elated.','She felt {exhilarated} after the bungee jump.','번지점프 후에 온몸이 짜릿했어요.','exhilarated','B2','emotion',1,'person exhilarated bungee jump adventure thrilled'),
('w_emotion_B2_06','remorseful','/rɪˈmɔːrsfəl/','adjective','뉘우치는, 후회하는','Feeling deep regret or guilt for wrongdoing.','He was deeply {remorseful} after hurting his friend.','친구에게 상처를 줘서 깊이 후회했어요.','remorseful','B2','emotion',1,'person remorseful regret apology sorry'),
('w_emotion_B2_07','indignant','/ɪnˈdɪɡnənt/','adjective','분개한','Feeling or showing anger about unjust treatment.','She was {indignant} when accused without evidence.','증거 없이 비난을 받자 분개했어요.','indignant','B2','emotion',2,'person indignant unfair accusation angry'),
('w_emotion_B2_08','compassionate','/kəmˈpæʃənət/','adjective','연민 어린, 동정심 있는','Feeling or showing sympathy and concern for others.','She was {compassionate} toward those who were suffering.','고통받는 사람들을 향해 연민을 느꼈어요.','compassionate','B2','emotion',1,'person compassionate helping others care'),
('w_emotion_B2_09','bewildered','/bɪˈwɪldərd/','adjective','당혹스러운, 어리둥절한','Completely puzzled or confused.','He looked {bewildered} by the contradictory instructions.','모순된 지시에 어리둥절해 보였어요.','bewildered','B2','emotion',1,'person bewildered confused contradictory'),
('w_emotion_B2_10','elated','/ɪˈleɪtɪd/','adjective','매우 기쁜, 의기양양한','Ecstatically happy and in high spirits.','She was {elated} when she got the scholarship.','장학금을 받았을 때 너무 기뻤어요.','elated','B2','emotion',1,'person elated scholarship success celebration'),
('w_emotion_B2_11','resentful','/rɪˈzentfəl/','adjective','억울한, 원망스러운','Feeling bitter and angry about unfair treatment.','He was {resentful} about being passed over for promotion.','승진에서 제외되어 억울함을 느꼈어요.','resentful','B2','emotion',2,'person resentful passed over work'),
('w_emotion_B2_12','ambivalent','/æmˈbɪvələnt/','adjective','양면적 감정을 가진','Having mixed or contradictory feelings about something.','She felt {ambivalent} about leaving her hometown.','고향을 떠나는 것에 복잡한 감정을 느꼈어요.','ambivalent','B2','emotion',2,'person ambivalent hometown leaving mixed feelings'),
('w_emotion_B2_13','serene','/səˈriːn/','adjective','평온한, 고요한','Calm, peaceful, and untroubled.','She felt {serene} sitting by the mountain lake.','산 호수 옆에 앉아 평온함을 느꼈어요.','serene','B2','emotion',2,'person serene mountain lake peaceful nature'),
('w_emotion_B2_14','agitated','/ˈædʒɪteɪtɪd/','adjective','동요된, 안절부절못하는','Feeling or appearing troubled or nervous.','He seemed {agitated} throughout the meeting.','그는 회의 내내 안절부절못하는 것 같았어요.','agitated','B2','emotion',2,'person agitated restless meeting nervous'),
('w_emotion_B2_15','despondent','/dɪˈspɒndənt/','adjective','낙심한','In low spirits from loss of hope.','She became {despondent} after repeated failures.','반복된 실패 후에 낙심했어요.','despondent','B2','emotion',2,'person despondent low spirits failure'),
('w_emotion_B2_16','elusive','/ɪˈluːsɪv/','adjective','잡히지 않는, 모호한','(of a feeling) difficult to define or describe.','Happiness sometimes feels {elusive} when you chase it.','행복은 쫓을수록 잡히지 않는 것 같아요.','elusive','B2','emotion',3,'abstract happiness chasing feeling'),
('w_emotion_B2_17','conflicted','/kənˈflɪktɪd/','adjective','내적으로 갈등하는','Having or showing confused or contradictory feelings.','She felt {conflicted} about accepting the job overseas.','해외 취업 제안을 수락할지 내적으로 갈등했어요.','conflicted','B2','emotion',2,'person conflicted decision making choice'),
('w_emotion_B2_18','devastated','/ˈdevəsteɪtɪd/','adjective','망연자실한, 크게 상심한','Very shocked and upset.','He was {devastated} by the sudden loss.','갑작스러운 상실에 크게 상심했어요.','devastated','B2','emotion',2,'person devastated grief loss sad'),
('w_emotion_B2_19','invigorated','/ɪnˈvɪɡəreɪtɪd/','adjective','활력을 얻은','Made to feel strong, healthy, and full of energy.','She felt {invigorated} after the cold shower.','찬물 샤워 후에 활력이 생겼어요.','invigorated','B2','emotion',2,'person invigorated shower morning energy'),
('w_emotion_B2_20','appalled','/əˈpɔːld/','adjective','경악한','Greatly dismayed or horrified.','She was {appalled} by the conditions in the shelter.','쉼터의 환경에 경악했어요.','appalled','B2','emotion',2,'person appalled horrified dismayed situation'),
('w_emotion_B2_21','humiliated','/hjuːˈmɪlɪeɪtɪd/','adjective','굴욕감을 느끼는','Made to feel ashamed and foolish.','He felt {humiliated} after being criticised in front of everyone.','모든 사람 앞에서 비판받아 굴욕감을 느꼈어요.','humiliated','B2','emotion',2,'person humiliated public criticism'),
('w_emotion_B2_22','vindicated','/ˈvɪndɪkeɪtɪd/','adjective','억울함이 풀린, 무죄를 증명받은','Cleared of blame or suspicion.','She felt completely {vindicated} when the truth came out.','진실이 밝혀지자 억울함이 완전히 풀렸어요.','vindicated','B2','emotion',3,'person vindicated truth revealed justice'),
('w_emotion_B2_23','anxious','/ˈæŋkʃəs/','adjective','몹시 열망하는','Very eager or concerned to do something.','He was {anxious} to make a good impression.','좋은 인상을 남기려고 몹시 애썼어요.','anxious','B2','emotion',2,'person eager impression meeting'),
('w_emotion_B2_24','disheartened','/dɪsˈhɑːrtənd/','adjective','낙담한, 의기소침한','Having lost determination or confidence.','She was {disheartened} by the lack of progress.','진전이 없어 의기소침해졌어요.','disheartened','B2','emotion',2,'person disheartened no progress discouraged'),
('w_emotion_B2_25','euphoric','/juːˈfɒrɪk/','adjective','행복감에 넘치는','Intensely happy and confident.','He felt {euphoric} after completing the marathon.','마라톤을 완주한 후 행복감에 넘쳤어요.','euphoric','B2','emotion',2,'person euphoric marathon finish line celebration'),
('w_emotion_B2_26','sullen','/ˈsʌlən/','adjective','시무룩한, 쌀쌀한','Bad-tempered and sulky;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_emotion_C1_01','despondent','/dɪˈspɒndənt/','adjective','낙심한, 절망에 빠진','In low spirits from loss of hope or courage.','She was {despondent} after losing the election.','선거에서 지고 낙심에 빠졌어요.','despondent','C1','emotion',1,'person despondent election failure hopeless'),
('w_emotion_C1_02','euphoric','/juːˈfɒrɪk/','adjective','극도의 행복감에 찬','Intensely happy and excited.','He felt {euphoric} after the team''s victory.','팀의 승리 후 극도의 행복감을 느꼈어요.','euphoric','C1','emotion',1,'team victory celebration euphoric crowd'),
('w_emotion_C1_03','ambivalent','/æmˈbɪvələnt/','adjective','상반된 감정이 공존하는','Having mixed and contradictory feelings simultaneously.','She felt {ambivalent} about the new opportunity.','새 기회에 대해 상반된 감정을 느꼈어요.','ambivalent','C1','emotion',1,'person ambivalent mixed feelings decision crossroads'),
('w_emotion_C1_04','disenchanted','/ˌdɪsɪnˈtʃɑːntɪd/','adjective','환멸을 느끼는','Disappointed that something was less good than you believed.','He became {disenchanted} with the corporate world.','그는 기업 세계에 환멸을 느끼게 됐어요.','disenchanted','C1','emotion',1,'person disenchanted office corporate disappointed'),
('w_emotion_C1_05','forlorn','/fərˈlɔːrn/','adjective','쓸쓸한, 버려진 느낌의','Pitifully sad and abandoned.','She looked {forlorn} sitting alone in the empty café.','텅 빈 카페에 혼자 앉아 쓸쓸해 보였어요.','forlorn','C1','emotion',2,'person forlorn alone empty cafe sad lonely'),
('w_emotion_C1_06','jubilant','/ˈdʒuːbɪlənt/','adjective','환호하는, 의기양양한','Feeling or expressing great happiness and triumph.','The crowd was {jubilant} after the championship win.','챔피언십 우승 후 군중은 환호했어요.','jubilant','C1','emotion',1,'crowd jubilant championship winning celebration'),
('w_emotion_C1_07','mortified','/ˈmɔːrtɪfaɪd/','adjective','몹시 창피한, 굴욕스러운','Feeling intense embarrassment or shame.','She was {mortified} when she called the teacher ''mum''.','선생님을 ''엄마''라고 불러서 몹시 창피했어요.','mortified','C1','emotion',1,'person mortified embarrassed mistake classroom'),
('w_emotion_C1_08','pensive','/ˈpensɪv/','adjective','생각에 잠긴','Engaged in deep or serious thought.','He sat in a {pensive} mood, staring at the horizon.','그는 수평선을 바라보며 생각에 잠겨 있었어요.','pensive','C1','emotion',1,'person pensive thinking horizon deep thought'),
('w_emotion_C1_09','wistful','/ˈwɪstfəl/','adjective','그리움이 섞인 아쉬움','Having a feeling of vague longing or regretful yearning.','She had a {wistful} look as she recalled her childhood.','어린 시절을 떠올리며 아쉬운 눈빛을 보냈어요.','wistful','C1','emotion',1,'person wistful childhood memories nostalgic'),
('w_emotion_C1_10','appalled','/əˈpɔːld/','adjective','경악한, 충격을 받은','Greatly dismayed or horrified by something.','He was {appalled} at the level of corruption.','부패의 수준에 경악했어요.','appalled','C1','emotion',1,'person appalled corruption shocked dismayed'),
('w_emotion_C1_11','disquieted','/dɪsˈkwaɪətɪd/','adjective','불안하게 된','Made to feel anxious or unsettled.','She felt {disquieted} by his evasive answers.','그의 얼버무리는 답변에 불안해졌어요.','disquieted','C1','emotion',2,'person disquieted uneasy evasive answer'),
('w_emotion_C1_12','elated','/ɪˈleɪtɪd/','adjective','기쁨에 넘치는','Ecstatically happy.','They were {elated} at the unexpected promotion.','예기치 않은 승진에 기쁨에 넘쳤어요.','elated','C1','emotion',2,'person elated promotion joyful work'),
('w_emotion_C1_13','perturbed','/pərˈtɜːrbd/','adjective','마음이 어지러운','Anxious or unsettled;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_emotion_C2_01','lugubrious','/luːˈɡuːbriəs/','adjective','음울한, 처량한','Looking or sounding sad and mournful.','He wore a {lugubrious} expression throughout the gathering.','모임 내내 처량한 표정을 하고 있었어요.','lugubrious','C2','emotion',1,'person lugubrious mournful gathering sad expression'),
('w_emotion_C2_02','sanguine','/ˈsæŋɡwɪn/','adjective','낙관적인, 자신감 있는','Optimistic, especially in a difficult situation.','She remained {sanguine} despite the dire forecasts.','암울한 전망에도 불구하고 낙관적이었어요.','sanguine','C2','emotion',1,'person sanguine optimistic confident difficult forecast'),
('w_emotion_C2_03','lachrymose','/ˈlækrɪmoʊs/','adjective','눈물을 잘 흘리는, 슬픔에 젖은','Tearful or given to weeping.','He became {lachrymose} whenever he heard that song.','그 노래를 들을 때마다 눈물이 났어요.','lachrymose','C2','emotion',1,'person lachrymose tearful song emotional'),
('w_emotion_C2_04','disconsolate','/dɪsˈkɒnsələt/','adjective','위로받을 수 없을 만큼 슬픈','Deeply unhappy and unable to be comforted.','She was {disconsolate} after the irreversible mistake.','되돌릴 수 없는 실수 이후 위로받을 수 없을 만큼 슬펐어요.','disconsolate','C2','emotion',1,'person disconsolate grief irreversible mistake'),
('w_emotion_C2_05','ebullient','/ɪˈbʊliənt/','adjective','활기가 넘치는, 넘쳐흐르는','Cheerful and full of energy.','She arrived in an {ebullient} mood, ready to celebrate.','그녀는 축하할 준비를 하며 활기가 넘치는 기분으로 도착했어요.','ebullient','C2','emotion',1,'person ebullient energetic celebrating mood'),
('w_emotion_C2_06','ineffable','/ɪnˈefəbəl/','adjective','말로 표현할 수 없는','Too great or extreme to be expressed in words.','There was an {ineffable} sense of peace in that moment.','그 순간 말로 표현할 수 없는 평화로움이 있었어요.','ineffable','C2','emotion',1,'abstract ineffable peace serene moment'),
('w_emotion_C2_07','equanimous','/ɪˈkwænɪməs/','adjective','평정심을 가진','Having mental calmness and composure.','She remained {equanimous} in the face of crisis.','위기 앞에서도 평정심을 유지했어요.','equanimous','C2','emotion',1,'person equanimous calm crisis composure'),
('w_emotion_C2_08','magnanimous','/mæɡˈnænɪməs/','adjective','관대한, 너그러운','Generous or forgiving, especially toward a rival or enemy.','She was {magnanimous} in victory, praising her opponent.','그녀는 승리 속에서도 관대하게 상대방을 칭찬했어요.','magnanimous','C2','emotion',1,'person magnanimous generous victory praising opponent'),
('w_emotion_C2_09','stoic','/ˈstoʊɪk/','adjective','감정을 드러내지 않는, 의연한','Enduring pain or hardship without showing feelings.','He faced the diagnosis with {stoic} acceptance.','그는 진단을 의연하게 받아들였어요.','stoic','C2','emotion',1,'person stoic diagnosis acceptance calm'),
('w_emotion_C2_10','languid','/ˈlæŋɡwɪd/','adjective','나른한, 무기력한','Having or showing a disinclination for physical effort.','She gazed {languid}ly out of the train window.','그녀는 나른하게 기차 창밖을 바라봤어요.','languid','C2','emotion',1,'person languid train window dreamy'),
('w_emotion_C2_11','turbulent','/ˈtɜːrbjʊlənt/','adjective','격동적인, 혼란스러운','Characterised by conflict, disorder, or confusion.','His teenage years were emotionally {turbulent}.','그의 십대 시절은 감정적으로 격동적이었어요.','turbulent','C2','emotion',2,'turbulent emotional teenage years conflict'),
('w_emotion_C2_12','imperturbable','/ˌɪmpərˈtɜːrbəbəl/','adjective','흔들리지 않는, 침착한','Unable to be upset or excited;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_weather_A1_01','sunny','/ˈsʌni/','adjective','화창한','Bright with sunlight and clear skies.','It''s a {sunny} day today.','오늘은 화창한 날이에요.','sunny','A1','weather',1,'sunny day blue sky bright'),
('w_weather_A1_02','rainy','/ˈreɪni/','adjective','비가 오는','Having a lot of rain.','I don''t like {rainy} weather.','저는 비 오는 날씨를 별로 좋아하지 않아요.','rainy','A1','weather',1,'rainy day puddles umbrella'),
('w_weather_A1_03','hot','/hɒt/','adjective','더운, 뜨거운','Having a high temperature.','It is very {hot} outside today.','오늘 밖이 정말 더워요.','hot','A1','weather',1,'hot summer sun heat'),
('w_weather_A1_04','cold','/koʊld/','adjective','추운, 차가운','Having a low temperature.','The weather is {cold} in January.','1월에는 날씨가 추워요.','cold','A1','weather',1,'cold winter snow frost'),
('w_weather_A1_05','windy','/ˈwɪndi/','adjective','바람이 부는','With a lot of wind.','It is very {windy} today.','오늘 바람이 많이 불어요.','windy','A1','weather',1,'windy trees blowing leaves'),
('w_weather_A1_06','cloudy','/ˈklaʊdi/','adjective','흐린','Covered with clouds.','The sky is {cloudy} this morning.','오늘 아침 하늘이 흐려요.','cloudy','A1','weather',1,'cloudy sky grey overcast'),
('w_weather_A1_07','snow','/snoʊ/','noun','눈','Frozen water that falls from the sky as soft white flakes.','The children love to play in the {snow}.','아이들은 눈 속에서 노는 걸 좋아해요.','snow','A1','weather',1,'snow white winter landscape'),
('w_weather_A1_08','warm','/wɔːrm/','adjective','따뜻한','At a comfortably high temperature.','Spring weather is usually {warm}.','봄 날씨는 보통 따뜻해요.','warm','A1','weather',1,'warm sunshine spring flowers'),
('w_weather_A1_09','cool','/kuːl/','adjective','선선한, 시원한','Pleasantly low in temperature.','The evening air feels {cool}.','저녁 공기가 선선하게 느껴져요.','cool','A1','weather',1,'cool breeze evening nature'),
('w_weather_A1_10','weather','/ˈweðər/','noun','날씨','The state of the atmosphere at a place and time.','What is the {weather} like today?','오늘 날씨가 어때요?','weather','A1','weather',1,'weather sky clouds sun'),
('w_weather_A1_11','rain','/reɪn/','noun','비','Water that falls from clouds as drops.','There will be {rain} this afternoon.','오늘 오후에 비가 올 거예요.','rain','A1','weather',1,'rain drops falling puddle'),
('w_weather_A1_12','sun','/sʌn/','noun','태양, 햇빛','The star that gives light and heat to the Earth.','The {sun} is very bright today.','오늘 햇빛이 정말 밝아요.','sun','A1','weather',1,'sun bright sky yellow'),
('w_weather_A1_13','wind','/wɪnd/','noun','바람','Air moving from one place to another.','The {wind} is blowing hard tonight.','오늘 밤 바람이 세게 불고 있어요.','wind','A1','weather',1,'wind trees branches blowing'),
('w_weather_A1_14','cloud','/klaʊd/','noun','구름','A white or grey mass in the sky made of water drops.','There are big {cloud}s in the sky.','하늘에 커다란 구름이 있어요.','cloud','A1','weather',2,'cloud white sky fluffy'),
('w_weather_A1_15','ice','/aɪs/','noun','얼음, 빙판','Frozen water.','Be careful — there is {ice} on the road.','조심하세요. 도로에 빙판이 있어요.','ice','A1','weather',2,'ice frozen road winter'),
('w_weather_A1_16','wet','/wet/','adjective','젖은, 비 오는','Covered with water or another liquid.','My shoes got {wet} in the rain.','빗속에서 신발이 젖었어요.','wet','A1','weather',2,'wet rain shoes puddle'),
('w_weather_A1_17','dry','/draɪ/','adjective','건조한','Free from moisture or liquid.','This summer has been very {dry}.','이번 여름은 정말 건조했어요.','dry','A1','weather',2,'dry cracked earth desert'),
('w_weather_A1_18','storm','/stɔːrm/','noun','폭풍','A period of bad weather with strong winds and rain.','A big {storm} hit the coast last night.','어젯밤 해안에 큰 폭풍이 왔어요.','storm','A1','weather',2,'storm dark clouds lightning'),
('w_weather_A1_19','umbrella','/ʌmˈbrelə/','noun','우산','A device for keeping off rain.','Don''t forget to bring your {umbrella}.','우산 가져가는 거 잊지 마세요.','umbrella','A1','weather',2,'umbrella rain protection'),
('w_weather_A1_20','coat','/koʊt/','noun','코트, 외투','A long outer garment worn to stay warm.','You should wear a {coat} today.','오늘은 코트를 입는 게 좋겠어요.','coat','A1','weather',2,'coat winter warm clothing'),
('w_weather_A1_21','season','/ˈsiːzən/','noun','계절','One of the four parts of the year: spring, summer, autumn, winter.','Summer is my favourite {season}.','여름이 제가 가장 좋아하는 계절이에요.','season','A1','weather',2,'season four spring summer autumn winter'),
('w_weather_A1_22','spring','/sprɪŋ/','noun','봄','The season between winter and summer.','The flowers bloom in {spring}.','봄에 꽃이 피어요.','spring','A1','weather',2,'spring flowers blossoms green'),
('w_weather_A1_23','summer','/ˈsʌmər/','noun','여름','The warmest season of the year.','It is very hot in {summer}.','여름에는 정말 더워요.','summer','A1','weather',2,'summer beach hot sunny'),
('w_weather_A1_24','winter','/ˈwɪntər/','noun','겨울','The coldest season of the year.','I love drinking hot cocoa in {winter}.','저는 겨울에 핫초코 마시는 걸 좋아해요.','winter','A1','weather',2,'winter snow cold cosy'),
('w_weather_A1_25','outside','/ˌaʊtˈsaɪd/','adverb','밖에, 야외에','In or to the open air.','It is raining {outside}.','밖에 비가 오고 있어요.','outside','A1','weather',3,'outside rain street'),
('w_weather_A1_26','sky','/skaɪ/','noun','하늘','The region of the atmosphere seen from Earth.','The {sky} is blue and clear today.','오늘 하늘이 파랗고 맑아요.','sky','A1','weather',3,'sky blue clear horizon'),
('w_weather_A1_27','temperature','/ˈtemprɪtʃər/','noun','기온, 온도','The degree of heat or cold measured on a scale.','The {temperature} will drop tonight.','오늘 밤 기온이 떨어질 거예요.','temperature','A1','weather',3,'temperature thermometer weather'),
('w_weather_A1_28','fog','/fɒɡ/','noun','안개','A thick cloud of water droplets near the ground.','Drive slowly because of the {fog}.','안개 때문에 천천히 운전하세요.','fog','A1','weather',3,'fog misty morning road'),
('w_weather_A1_29','sunshine','/ˈsʌnʃaɪn/','noun','햇살','Direct light from the sun.','We had lovely {sunshine} all weekend.','주말 내내 멋진 햇살이 가득했어요.','sunshine','A1','weather',3,'sunshine bright warm light'),
('w_weather_A1_30','rainbow','/ˈreɪnboʊ/','noun','무지개','An arch of colours in the sky after rain.','Look at that beautiful {rainbow}!','저 예쁜 무지개 좀 봐요!','rainbow','A1','weather',3,'rainbow colourful sky after rain'),
('w_weather_A1_31','hail','/heɪl/','noun','우박','Pellets of frozen rain that fall from the sky.','The {hail} damaged many car rooftops.','우박이 많은 차 지붕을 망가뜨렸어요.','hail','A1','weather',3,'hail ice pellets storm'),
('w_weather_A1_32','thunder','/ˈθʌndər/','noun','천둥','The loud noise heard during a storm.','The {thunder} woke me up last night.','어젯밤에 천둥 소리에 잠이 깼어요.','thunder','A1','weather',3,'thunder storm lightning'),
('w_weather_A1_33','lightning','/ˈlaɪtnɪŋ/','noun','번개','A flash of bright light in the sky during a storm.','We saw {lightning} in the distance.','멀리서 번개가 보였어요.','lightning','A1','weather',3,'lightning flash storm night'),
('w_weather_A1_34','flood','/flʌd/','noun','홍수','An overflow of water over normally dry land.','Heavy rain caused a {flood} in the town.','폭우로 마을에 홍수가 났어요.','flood','A1','weather',3,'flood water street submerged'),
('w_weather_A1_35','autumn','/ˈɔːtəm/','noun','가을','The season between summer and winter.','The leaves turn red in {autumn}.','가을에 나뭇잎이 빨갛게 물들어요.','autumn','A1','weather',3,'autumn leaves red orange fall');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_weather_A2_01','forecast','/ˈfɔːrkæst/','noun','일기 예보','A statement about what the weather will be like in the future.','The {forecast} says it will snow tomorrow.','예보에서 내일 눈이 온다고 해요.','forecast','A2','weather',1,'forecast weather map prediction'),
('w_weather_A2_02','temperature','/ˈtemprɪtʃər/','noun','기온','The degree of heat or coldness measured on a specific scale.','The {temperature} reached 35 degrees today.','오늘 기온이 35도까지 올랐어요.','temperature','A2','weather',1,'temperature thermometer heat'),
('w_weather_A2_03','humid','/ˈhjuːmɪd/','adjective','습한','Having a lot of water vapour in the air.','Seoul is very {humid} in August.','서울은 8월에 정말 습해요.','humid','A2','weather',1,'humid sticky air tropics'),
('w_weather_A2_04','thunder','/ˈθʌndər/','noun','천둥','The loud rumbling sound that follows lightning.','There was a big {thunder} storm overnight.','밤새 엄청난 천둥 번개가 쳤어요.','thunder','A2','weather',1,'thunder storm dark sky'),
('w_weather_A2_05','lightning','/ˈlaɪtnɪŋ/','noun','번개','A flash of light caused by electricity in the atmosphere.','The {lightning} lit up the whole sky.','번개가 하늘 전체를 밝혔어요.','lightning','A2','weather',1,'lightning bolt night sky'),
('w_weather_A2_06','fog','/fɒɡ/','noun','안개','A dense cloud of tiny water droplets near the ground.','The airport was closed because of thick {fog}.','짙은 안개로 공항이 폐쇄됐어요.','fog','A2','weather',1,'fog thick misty road'),
('w_weather_A2_07','frost','/frɒst/','noun','서리','A thin layer of ice that forms on surfaces when temperatures drop below freezing.','There was {frost} on the grass this morning.','오늘 아침 풀잎에 서리가 내렸어요.','frost','A2','weather',1,'frost ice grass morning'),
('w_weather_A2_08','drizzle','/ˈdrɪzəl/','noun','이슬비, 부슬비','Light rain falling in very small drops.','It''s just a light {drizzle} — you don''t need an umbrella.','가벼운 이슬비라 우산은 필요 없어요.','drizzle','A2','weather',1,'drizzle light rain mist'),
('w_weather_A2_09','breeze','/briːz/','noun','산들바람','A gentle, light wind.','A cool {breeze} came in through the window.','시원한 산들바람이 창문으로 들어왔어요.','breeze','A2','weather',1,'breeze gentle wind leaves'),
('w_weather_A2_10','shower','/ˈʃaʊər/','noun','소나기','A brief fall of rain.','There will be afternoon {shower}s today.','오늘 오후에 소나기가 내릴 거예요.','shower','A2','weather',2,'shower rain afternoon brief'),
('w_weather_A2_11','overcast','/ˌoʊvərˈkæst/','adjective','잔뜩 흐린','(Of the sky) covered with cloud.','The sky is completely {overcast} today.','오늘 하늘이 완전히 흐려요.','overcast','A2','weather',2,'overcast grey sky clouds'),
('w_weather_A2_12','blizzard','/ˈblɪzərd/','noun','눈보라','A severe snowstorm with strong winds.','The {blizzard} shut down the whole city.','눈보라로 도시 전체가 마비됐어요.','blizzard','A2','weather',2,'blizzard snowstorm winter'),
('w_weather_A2_13','heatwave','/ˈhiːtweɪv/','noun','폭염, 열파','A prolonged period of abnormally hot weather.','Many elderly people suffer during a {heatwave}.','폭염 중에 노인분들이 많이 힘들어하세요.','heatwave','A2','weather',2,'heatwave hot sun dry'),
('w_weather_A2_14','slippery','/ˈslɪpəri/','adjective','미끄러운','Difficult to stand on or hold because of a smooth or wet surface.','The roads are {slippery} after the snow.','눈이 온 후 도로가 미끄러워요.','slippery','A2','weather',2,'slippery road ice winter'),
('w_weather_A2_15','humid','/ˈhjuːmɪd/','adjective','습한, 눅눅한','(Already listed at A2_03 — variant entry for classroom use) Feeling damp and warm.','The air is so {humid} that my hair is frizzy.','공기가 너무 습해서 머리가 부풀었어요.','humid','A2','weather',2,'humid air sticky tropical'),
('w_weather_A2_16','chilly','/ˈtʃɪli/','adjective','쌀쌀한','Unpleasantly cold.','It gets {chilly} in the evening here.','이곳은 저녁에 쌀쌀해져요.','chilly','A2','weather',2,'chilly cold evening autumn'),
('w_weather_A2_17','mild','/maɪld/','adjective','온화한','(Of weather) not extreme;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_weather_B1_01','humidity','/hjuːˈmɪdɪti/','noun','습도','The amount of water vapour in the air.','The {humidity} today makes it feel hotter than it is.','오늘 습도 때문에 실제보다 더 덥게 느껴져요.','humidity','B1','weather',1,'humidity sticky tropical air'),
('w_weather_B1_02','precipitation','/prɪˌsɪpɪˈteɪʃən/','noun','강수량, 강수','Water that falls from the sky as rain, snow, sleet, or hail.','Monthly {precipitation} levels have been unusually high.','월 강수량이 예년에 비해 유독 높아요.','precipitation','B1','weather',1,'precipitation rain snow measurement'),
('w_weather_B1_03','visibility','/ˌvɪzɪˈbɪlɪti/','noun','가시거리, 시정','The distance at which objects can be clearly seen.','Poor {visibility} is making driving dangerous.','낮은 가시거리로 운전이 위험해요.','visibility','B1','weather',1,'visibility fog road distance'),
('w_weather_B1_04','heatwave','/ˈhiːtweɪv/','noun','폭염','A prolonged period of abnormally hot weather.','The {heatwave} broke records across the country.','폭염이 전국적으로 기록을 깨뜨렸어요.','heatwave','B1','weather',1,'heatwave extreme heat dry summer'),
('w_weather_B1_05','drought','/draʊt/','noun','가뭄','A long period of very little or no rain.','Farmers are struggling because of the {drought}.','농부들이 가뭄 때문에 힘들어하고 있어요.','drought','B1','weather',1,'drought dry cracked earth'),
('w_weather_B1_06','blizzard','/ˈblɪzərd/','noun','눈보라','A severe snowstorm with strong, blinding winds.','Flights were cancelled due to the {blizzard}.','눈보라로 항공편이 취소됐어요.','blizzard','B1','weather',1,'blizzard snowstorm white out'),
('w_weather_B1_07','overcast','/ˌoʊvərˈkæst/','adjective','잔뜩 흐린','(Of the sky) covered with a thick layer of grey cloud.','It''s {overcast} today, so bring a jacket.','오늘 날씨가 흐리니까 재킷을 챙기세요.','overcast','B1','weather',1,'overcast grey sky heavy clouds'),
('w_weather_B1_08','mild','/maɪld/','adjective','온화한','Pleasantly warm and without extreme cold or heat.','The climate here is {mild} all year round.','이곳 기후는 연중 온화해요.','mild','B1','weather',1,'mild weather pleasant countryside'),
('w_weather_B1_09','chilly','/ˈtʃɪli/','adjective','쌀쌀한','Noticeably cold, causing discomfort.','It''s quite {chilly} in the shade.','그늘에는 꽤 쌀쌀해요.','chilly','B1','weather',1,'chilly autumn cold evening'),
('w_weather_B1_10','tropical','/ˈtrɒpɪkəl/','adjective','열대의','Relating to the tropics;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_weather_B2_01','meteorology','/ˌmiːtiəˈrɒlədʒi/','noun','기상학','The scientific study of the atmosphere and weather.','She studied {meteorology} at university.','그녀는 대학에서 기상학을 공부했어요.','meteorology','B2','weather',1,'meteorology science atmosphere'),
('w_weather_B2_02','atmospheric','/ˌætməsˈferɪk/','adjective','대기의','Relating to the atmosphere of the Earth.','{Atmospheric} pressure affects how we feel.','대기압은 우리의 기분에 영향을 미쳐요.','atmospheric','B2','weather',1,'atmospheric pressure sky science'),
('w_weather_B2_03','cyclone','/ˈsaɪkloʊn/','noun','사이클론, 열대 저기압','A system of winds rotating inward to an area of low pressure.','The {cyclone} caused widespread flooding.','사이클론이 광범위한 홍수를 일으켰어요.','cyclone','B2','weather',1,'cyclone storm tropical spinning'),
('w_weather_B2_04','monsoon','/ˌmɒnˈsuːn/','noun','몬순, 우기','A seasonal wind bringing heavy rain to South and Southeast Asia.','The {monsoon} season in India lasts from June to September.','인도의 몬순 시즌은 6월부터 9월까지예요.','monsoon','B2','weather',1,'monsoon rain India tropical'),
('w_weather_B2_05','arid','/ˈærɪd/','adjective','건조한, 불모의','Having very little or no rain;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_weather_C1_01','climatology','/ˌklaɪməˈtɒlədʒi/','noun','기후학','The scientific study of climate.','{Climatology} provides the data needed for climate policy.','기후학은 기후 정책에 필요한 데이터를 제공해요.','climatology','C1','weather',1,'climatology science data research'),
('w_weather_C1_02','microclimate','/ˈmaɪkrəʊˌklaɪmɪt/','noun','미기후','The climate of a very small or restricted area, often different from the surrounding region.','Urban parks can create their own {microclimate}.','도시 공원은 자체적인 미기후를 만들 수 있어요.','microclimate','C1','weather',1,'microclimate urban park local climate'),
('w_weather_C1_03','inversion','/ɪnˈvɜːrʒən/','noun','기온 역전','A reversal of the normal decrease in temperature with altitude.','A temperature {inversion} trapped pollutants near the ground.','기온 역전이 오염 물질을 지표 근처에 가두었어요.','inversion','C1','weather',1,'temperature inversion smog valley'),
('w_weather_C1_04','stratosphere','/ˈstrætəsfɪər/','noun','성층권','The layer of Earth''s atmosphere above the troposphere, extending to about 50 km.','Volcanic ash can reach the {stratosphere}.','화산재가 성층권에 도달할 수 있어요.','stratosphere','C1','weather',1,'stratosphere atmosphere layers'),
('w_weather_C1_05','El Niño','/el ˈniːnjəʊ/','noun','엘니뇨','A periodic warming of ocean surface temperatures in the central and eastern Pacific.','{El Niño} causes droughts in some regions and floods in others.','엘니뇨는 일부 지역에 가뭄을, 다른 지역에 홍수를 가져와요.','El Niño','C1','weather',1,'El Nino Pacific ocean warming'),
('w_weather_C1_06','anomaly','/əˈnɒməli/','noun','편차, 이상','A deviation from the expected or typical pattern.','Scientists recorded a record temperature {anomaly} last year.','과학자들이 지난해 기록적인 기온 편차를 기록했어요.','anomaly','C1','weather',1,'anomaly temperature record data'),
('w_weather_C1_07','deviation','/ˌdiːviˈeɪʃən/','noun','편차','The amount by which a value differs from a standard or average.','A {deviation} of just 2°C can significantly impact ecosystems.','단 2도의 편차도 생태계에 상당한 영향을 미칠 수 있어요.','deviation','C1','weather',1,'deviation chart statistics climate'),
('w_weather_C1_08','temperate','/ˈtempərɪt/','adjective','온대의, 온화한','Having mild temperatures;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_weather_C2_01','paleoclimatology','/ˌpeɪliəʊˌklaɪməˈtɒlədʒi/','noun','고기후학','The study of past climates through geological, biological, and chemical evidence.','{Paleoclimatology} reveals how Earth''s climate has changed over millennia.','고기후학은 수천 년에 걸친 지구 기후 변화를 밝혀줘요.','paleoclimatology','C2','weather',1,'paleoclimatology ice core fossil climate'),
('w_weather_C2_02','anthropogenic','/ˌænθrəpəˈdʒenɪk/','adjective','인위적인, 인간 활동에 의한','Originating in human activity.','Most of today''s climate change is {anthropogenic}.','오늘날 기후 변화의 대부분은 인위적인 것이에요.','anthropogenic','C2','weather',1,'anthropogenic pollution industry CO2'),
('w_weather_C2_03','biogeochemical','/ˌbaɪəʊˌdʒiːəʊˈkemɪkəl/','adjective','생물 지구 화학적','Relating to the chemical, biological, and geological cycles of the Earth.','{Biogeochemical} cycles control how nutrients move through ecosystems.','생물 지구 화학적 순환은 생태계의 영양소 이동을 조절해요.','biogeochemical','C2','weather',1,'biogeochemical cycle carbon nitrogen'),
('w_weather_C2_04','teleconnection','/ˈteliːkəˌnekʃən/','noun','원격 상관','A correlation between weather or climate anomalies separated by large distances.','{Teleconnection}s help forecast droughts months in advance.','원격 상관은 몇 달 전에 가뭄을 예측하는 데 도움을 줘요.','teleconnections','C2','weather',1,'teleconnection global climate pattern map'),
('w_weather_C2_05','thermohaline','/ˌθɜːrməʊˈheɪlaɪn/','adjective','열염 (온도와 염도에 의한)','Relating to ocean circulation driven by temperature and salinity differences.','The {thermohaline} conveyor belt could weaken with freshwater influx.','담수 유입으로 열염 컨베이어 벨트가 약해질 수 있어요.','thermohaline','C2','weather',1,'thermohaline ocean circulation belt'),
('w_weather_C2_06','albedo','/ælˈbiːdəʊ/','noun','알베도','The fraction of solar energy reflected from the Earth back into space.','Reduced {albedo} from melting ice accelerates warming.','빙하 녹음으로 인한 알베도 감소가 온난화를 가속해요.','albedo','C2','weather',1,'albedo reflection ice surface'),
('w_weather_C2_07','radiative forcing','/ˈreɪdiətɪv ˈfɔːrsɪŋ/','noun','복사 강제력','The imbalance in Earth''s energy budget caused by changes in greenhouse gas concentrations.','Increased {radiative forcing} is the primary driver of climate change.','증가된 복사 강제력이 기후 변화의 주요 원인이에요.','radiative forcing','C2','weather',1,'radiative forcing greenhouse energy'),
('w_weather_C2_08','permafrost','/ˈpɜːrməfrɒst/','noun','영구 동토층','Ground in polar regions that remains continuously frozen for two or more years.','The thawing of {permafrost} releases ancient carbon stores.','영구 동토층의 해빙은 오래된 탄소 저장량을 방출해요.','permafrost','C2','weather',1,'permafrost thaw Arctic tundra methane'),
('w_weather_C2_09','dendroclimatology','/ˌdendrəʊˌklaɪməˈtɒlədʒi/','noun','수목 연륜 기후학','The study of past climates by analysing the annual growth rings of trees.','{Dendroclimatology} can reconstruct 500 years of climate data.','수목 연륜 기후학은 500년간의 기후 데이터를 재구성할 수 있어요.','dendroclimatology','C2','weather',1,'dendroclimatology tree rings climate'),
('w_weather_C2_10','proxy','/ˈprɒksi/','noun','대리 지표','Indirect evidence used to reconstruct past climate conditions.','Ice cores are the most valuable climate {proxy}.','빙하 코어는 가장 귀중한 기후 대리 지표예요.','proxy','C2','weather',1,'proxy ice core climate data'),
('w_weather_C2_11','insolation','/ˌɪnsəˈleɪʃən/','noun','일사량','The amount of solar radiation reaching a surface.','Seasonal changes in {insolation} drive the annual temperature cycle.','일사량의 계절적 변화가 연간 기온 순환을 이끌어요.','insolation','C2','weather',2,'insolation solar radiation surface earth'),
('w_weather_C2_12','Milankovitch cycles','/mɪˈlæŋkəvɪtʃ ˈsaɪkəlz/','noun','밀란코비치 주기','Long-term variations in Earth''s orbital parameters that affect climate.','{Milankovitch cycles} explain the timing of ice ages.','밀란코비치 주기는 빙하기 시기를 설명해요.','Milankovitch cycles','C2','weather',2,'Milankovitch cycles orbit earth ice age'),
('w_weather_C2_13','cryosphere','/ˈkraɪəsfɪər/','noun','빙권','The frozen water parts of Earth, including glaciers, ice sheets, and sea ice.','The {cryosphere} is shrinking at an unprecedented rate.','빙권이 전례 없는 속도로 축소되고 있어요.','cryosphere','C2','weather',2,'cryosphere ice glacier Arctic Antarctic'),
('w_weather_C2_14','hydrological cycle','/ˌhaɪdrəˈlɒdʒɪkəl ˈsaɪkəl/','noun','물 순환 (수문 순환)','The continuous movement of water through Earth''s systems.','Climate change is intensifying the {hydrological cycle}.','기후 변화가 물 순환을 강화하고 있어요.','hydrological cycle','C2','weather',2,'hydrological cycle water rain evaporation'),
('w_weather_C2_15','stratospheric warming','/ˌstrætəˈsferɪk ˈwɔːrmɪŋ/','noun','성층권 온난화','A sudden increase in stratospheric temperature that can disrupt polar vortex.','Sudden {stratospheric warming} events weaken the polar vortex.','갑작스러운 성층권 온난화 사건이 극 소용돌이를 약화시켜요.','stratospheric warming','C2','weather',3,'stratospheric warming polar vortex'),
('w_weather_C2_16','carbon sequestration','/ˈkɑːrbən ˌsiːkwɪˈstreɪʃən/','noun','탄소 격리','The long-term storage of carbon dioxide to reduce greenhouse gas concentrations.','Reforestation is a key strategy for {carbon sequestration}.','산림 복원은 탄소 격리의 핵심 전략이에요.','carbon sequestration','C2','weather',2,'carbon sequestration forest trees soil'),
('w_weather_C2_17','cloud albedo effect','/klaʊd ælˈbiːdəʊ ɪˈfekt/','noun','구름 알베도 효과','The cooling influence of clouds reflecting solar radiation back into space.','The {cloud albedo effect} is a major source of uncertainty in climate models.','구름 알베도 효과는 기후 모델의 주요 불확실성 원인이에요.','cloud albedo effect','C2','weather',3,'cloud albedo reflection climate model'),
('w_weather_C2_18','isotope analysis','/ˈaɪsətəʊp əˈnæləsɪs/','noun','동위원소 분석','The use of stable isotope ratios in ice or sediment cores to reconstruct past climates.','{Isotope analysis} revealed a sudden cooling 12,000 years ago.','동위원소 분석으로 12,000년 전의 갑작스러운 냉각이 밝혀졌어요.','isotope analysis','C2','weather',3,'isotope analysis ice core paleoclimate'),
('w_weather_C2_19','biogenic volatile organic compound','/baɪəˈdʒenɪk vəˈlætaɪl ɔːrˈɡænɪk ˈkɒmpaʊnd/','noun','생물 기원 휘발성 유기화합물','Organic chemicals emitted by vegetation that affect air chemistry and cloud formation.','Forests emit {biogenic volatile organic compound}s that influence regional climate.','숲은 지역 기후에 영향을 미치는 생물 기원 휘발성 유기화합물을 방출해요.','BVOCs','C2','weather',3,'BVOC forest emission aerosol'),
('w_weather_C2_20','abrupt climate change','/əˈbrʌpt ˈklaɪmɪt tʃeɪndʒ/','noun','급격한 기후 변화','A large-scale change in the climate system that takes place over a few decades or less.','Evidence shows {abrupt climate change} has occurred many times in Earth''s history.','지구 역사에서 급격한 기후 변화가 여러 번 발생했다는 증거가 있어요.','abrupt climate change','C2','weather',2,'abrupt climate change sudden shift data'),
('w_weather_C2_21','solar irradiance','/ˈsoʊlər ɪˈreɪdiəns/','noun','태양 복사량','The total power of solar energy received per unit area.','Variations in {solar irradiance} are a natural climate driver.','태양 복사량의 변화는 자연적인 기후 요인이에요.','solar irradiance','C2','weather',2,'solar irradiance sun energy measurement'),
('w_weather_C2_22','feedback mechanism','/ˈfiːdbæk ˈmekənɪzəm/','noun','피드백 메커니즘','A process in which the output of a system influences that system''s future behaviour.','Water vapour is a powerful positive {feedback mechanism} in the climate system.','수증기는 기후 시스템에서 강력한 양의 피드백 메커니즘이에요.','feedback mechanism','C2','weather',2,'feedback mechanism climate water vapour'),
('w_weather_C2_23','global mean surface temperature','/ˈɡloʊbəl miːn ˈsɜːrfɪs ˈtemprɪtʃər/','noun','전 지구 평균 지표 기온','The globally averaged temperature of Earth''s surface.','The {global mean surface temperature} has risen by 1.2°C since pre-industrial times.','전 지구 평균 지표 기온은 산업화 이전보다 1.2도 상승했어요.','GMST','C2','weather',2,'global mean temperature chart rise'),
('w_weather_C2_24','forcing agent','/ˈfɔːrsɪŋ ˈeɪdʒənt/','noun','복사 강제 인자','A factor that causes a change in Earth''s energy balance.','Methane is a potent {forcing agent} in climate change.','메탄은 기후 변화에서 강력한 복사 강제 인자예요.','forcing agent','C2','weather',3,'forcing agent methane CO2 climate'),
('w_weather_C2_25','sea ice extent','/siː aɪs ɪkˈstent/','noun','해빙 면적','The total area of the ocean surface covered by sea ice.','Arctic {sea ice extent} is declining faster than predicted.','북극 해빙 면적이 예측보다 빠르게 줄어들고 있어요.','sea ice extent','C2','weather',2,'sea ice Arctic extent satellite'),
('w_weather_C2_26','ice age','/aɪs eɪdʒ/','noun','빙하기','A period of long-term reduction in global temperature resulting in glaciation.','We are currently in an interglacial period of the current {ice age}.','우리는 현재 빙하기의 간빙기에 살고 있어요.','ice age','C2','weather',2,'ice age glacial period Earth'),
('w_weather_C2_27','water vapour feedback','/ˈwɔːtər ˈveɪpər ˈfiːdbæk/','noun','수증기 피드백','The amplification of warming caused by increased water vapour in the atmosphere.','{Water vapour feedback} more than doubles initial warming from CO₂.','수증기 피드백은 CO₂로 인한 초기 온난화를 두 배 이상으로 증폭시켜요.','water vapour feedback','C2','weather',3,'water vapour feedback climate warming'),
('w_weather_C2_28','palaeotemperature','/ˌpeɪliəʊˈtemprɪtʃər/','noun','고대 기온','A reconstructed temperature of a past period inferred from proxy data.','{Palaeotemperature} records from ice cores show rapid swings.','빙하 코어의 고대 기온 기록은 급격한 변동을 보여줘요.','palaeotemperature','C2','weather',3,'palaeotemperature ice core proxy data'),
('w_weather_C2_29','heterogeneous nucleation','/ˌhetərəˈdʒiːniəs ˌnjuːkliˈeɪʃən/','noun','불균일 핵 생성','The formation of ice crystals or water droplets on aerosol particles.','{Heterogeneous nucleation} is the main process forming cloud droplets.','불균일 핵 생성이 구름 물방울 형성의 주요 과정이에요.','heterogeneous nucleation','C2','weather',3,'nucleation cloud droplets aerosol'),
('w_weather_C2_30','integrated assessment model','/ˈɪntɪɡreɪtɪd əˈsesmənt ˈmɒdəl/','noun','통합 평가 모델','A computer model combining climate science and socioeconomic analysis.','{Integrated assessment model}s project warming under different emission pathways.','통합 평가 모델들은 다양한 배출 경로에서의 온난화를 전망해요.','IAM','C2','weather',3,'integrated assessment model climate projection'),
('w_weather_C2_31','carbon budget','/ˈkɑːrbən ˈbʌdʒɪt/','noun','탄소 예산','The maximum amount of CO₂ that can be emitted to stay within a temperature limit.','The world has used most of its 1.5°C {carbon budget}.','세계는 1.5도 탄소 예산의 대부분을 이미 사용했어요.','carbon budget','C2','weather',2,'carbon budget CO2 budget emissions'),
('w_weather_C2_32','emission pathway','/ɪˈmɪʃən ˈpɑːθweɪ/','noun','배출 경로','A trajectory describing future greenhouse gas emissions over time.','Choosing a steep {emission pathway} reduction is critical.','가파른 배출 경로 감소를 선택하는 것이 매우 중요해요.','emission pathway','C2','weather',2,'emission pathway CO2 reduction graph'),
('w_weather_C2_33','net zero','/net ˈzɪərəʊ/','noun','탄소 중립, 넷 제로','A state in which the greenhouse gases emitted are balanced by those removed from the atmosphere.','Many countries have pledged to achieve {net zero} by 2050.','많은 나라들이 2050년까지 탄소 중립 달성을 약속했어요.','net zero','C2','weather',2,'net zero carbon neutral target'),
('w_weather_C2_34','tectonic influence','/tekˈtɒnɪk ˈɪnfluəns/','noun','지각 변동의 영향','The effect of plate movement on long-term climate by reshaping landmasses and sea levels.','{Tectonic influence} shaped Earth''s climate over geological time.','지각 변동의 영향이 지질학적 시간에 걸쳐 지구 기후를 형성했어요.','tectonic influence','C2','weather',3,'tectonic plates climate geology'),
('w_weather_C2_35','deep time climate','/diːp taɪm ˈklaɪmɪt/','noun phrase','심층 시간 기후 (지질학적 기후)','Climate conditions of geological eons, studied through rock and fossil records.','Understanding {deep time climate} helps contextualise modern warming.','심층 시간 기후를 이해하면 현대 온난화를 더 잘 이해할 수 있어요.','deep time climate','C2','weather',3,'deep time climate fossil geology record');
